/**
 * scenarios.js — 60 scénarios officiels de l'épreuve "questions dans la voiture".
 * Source : DSR/BRPCE (jan. 2018). Numérotation : 2 derniers chiffres du compteur.
 * IDs 00-60 couverts. Les autres scénarios seront ajoutés progressivement.
 *
 * Chaque objet contient :
 *   id       : "00"–"40"
 *   type1    : "VI" (vérification intérieure) | "VE" (vérification extérieure)
 *   q1/a1    : question et réponse officielle de vérification
 *   explain1 : explication pédagogique (pourquoi c'est important)
 *   photo1   : nom de fichier image dans /public/photos/ (optionnel)
 *   q2/a2    : question et réponse QSER (sécurité routière)
 *   explain2 : explication QSER
 *   q3/a3    : question et réponse premiers secours
 *   explain3 : explication premiers secours
 */

export const SCENARIOS = [
  {"id":"01","type1":"VI","q1":"Montrez la commande de réglage de hauteur des feux.","a1":"Dispositif situé en général à gauche du volant.","explain1":"Ce correcteur de site adapte l'angle des feux à la charge. Plus la voiture est chargée à l'arrière, plus les feux pointent vers le haut — risque d'éblouir les autres.","photo1":"correcteur-feux.jpg","q2":"Pourquoi doit-on régler la hauteur des feux ?","a2":"Pour ne pas éblouir les autres usagers.","explain2":"Un mauvais réglage réduit la visibilité des conducteurs en face. C'est aussi un point vérifié au contrôle technique.","q3":"Comment et pourquoi protéger une zone de danger en cas d'accident de la route ?","a3":"En délimitant clairement et largement la zone de danger de façon visible pour protéger les victimes et éviter un sur-accident.","explain3":"Le sur-accident est fréquent et mortel. Baliser large et tôt est la priorité AVANT les premiers secours."},
  {"id":"02","type1":"VE","q1":"Montrez où s'effectue le remplissage du produit lave-glace.","a1":"Ouvrir le capot et montrer le bocal lave-glace (bouchon bleu en général).","explain1":"Ne jamais confondre avec le liquide de refroidissement. Mettre du lave-glace dans le mauvais réservoir peut endommager le moteur.","photo1":"bocal-lave-glace.jpg","q2":"Pourquoi est-il préférable d'utiliser un liquide lave-glace spécial en hiver ?","a2":"Pour éviter le gel du liquide.","explain2":"Un liquide gelé bloque les gicleurs ou fait éclater le bocal. Utiliser un liquide antigel adapté à -20°C min.","q3":"Quels comportements adopter en cas de diffusion du signal d'alerte du SAIP ?","a3":"Se mettre en sécurité. S'informer via les médias et sites des autorités. Respecter les consignes des autorités.","explain3":"SAIP = danger imminent (catastrophe, attentat…). L'appli SAIP envoie aussi des alertes push sur smartphone."},
  {"id":"03","type1":"VI","q1":"Mettez le rétroviseur intérieur en position « nuit ».","a1":"Basculer la languette sous le rétroviseur, ou indiquer le système automatique si équipé.","explain1":"La position nuit incline le miroir pour renvoyer les phares arrière vers le bas. Sans ça, éblouissement direct à 90 km/h = 125 m 'à l'aveugle'.","photo1":"retroviseur-nuit.jpg","q2":"Quel est l'intérêt de la position nuit ?","a2":"Ne pas être ébloui par les feux du véhicule suiveur.","explain2":"L'éblouissement provoque 2 à 5 secondes de cécité temporaire. À 90 km/h = 125 m sans visibilité.","q3":"Comment est composé le signal d'alerte du SAIP diffusé par les sirènes ?","a3":"Deux codes : Signal National d'Alerte (SNA) = variation sur 3 cycles successifs. Signal de fin d'alerte = signal continu.","explain3":"Signal modulé (montée/descente) = danger en cours. Signal continu = fin d'alerte. À connaître pour ne pas paniquer inutilement."},
  {"id":"04","type1":"VE","q1":"Contrôlez l'état du flanc sur l'un des pneumatiques.","a1":"Vérification visuelle du flanc : en bon état, sans coupure, boursouflure ni déformation. Toute anomalie doit être signalée.","explain1":"Le flanc est la partie la plus fragile du pneu (chocs de trottoir). Une boursouflure = risque d'éclatement imminent.","photo1":"flanc-pneumatique.jpg","q2":"Citez un endroit où l'on peut trouver les pressions préconisées pour les pneumatiques.","a2":"Sur une plaque sur une portière, dans la notice d'utilisation, ou au niveau de la trappe à carburant.","explain2":"La pression varie selon la charge et l'essieu. Toujours vérifier à froid. Sous-gonflage = surchauffe + usure anormale.","requiredCount2":1,"q3":"Sur autoroute, comment indiquer avec précision les lieux d'un accident depuis un téléphone portable ?","a3":"En indiquant le numéro de l'autoroute, le sens de circulation et le point kilométrique.","explain3":"Les bornes d'appel orange (tous les 2 km) transmettent automatiquement la position — idéales après une panne."},
  {"id":"05","type1":"VI","q1":"Faites fonctionner les essuie-glaces avants du véhicule sur la position la plus rapide.","a1":"Actionner le levier des essuie-glaces sur la colonne de direction et le placer sur la position la plus rapide.","explain1":"Les positions vont d'intermittent à rapide. En fortes pluies, la vitesse max est indispensable pour maintenir la visibilité.","photo1":"levier-essuie-glaces.jpg","q2":"Comment détecter l'usure des essuie-glaces en circulation ?","a2":"En cas de pluie, lorsqu'ils laissent des traces sur le pare-brise.","explain2":"Stries ou zones non essuyées = caoutchouc durci ou abîmé. À changer avant l'hiver, tous les 1-2 ans.","q3":"Comment vérifier la respiration d'une victime ?","a3":"Regarder si le ventre et la poitrine se soulèvent, et sentir de l'air à l'expiration.","explain3":"Technique LVA : Voir, Écouter, Sentir pendant 10 secondes. Pas de respiration → commencer la RCP immédiatement."},
  {"id":"06","type1":"VE","q1":"Vérifiez l'état et la propreté des plaques d'immatriculation.","a1":"Vérification des plaques avant et arrière : propres, lisibles et en bon état. Toute anomalie doit être signalée.","explain1":"Une plaque illisible constitue une infraction. Elle doit être visible de nuit grâce à l'éclairage de plaque.","photo1":"plaque-immatriculation.jpg","q2":"Quelles sont les précautions à prendre en cas d'installation d'un porte-vélo ?","a2":"La plaque d'immatriculation et les feux doivent rester visibles.","explain2":"Un porte-vélo masquant la plaque ou les feux est illégal. Il faut fixer une plaque et des feux déportés sur le porte-vélo.","q3":"Qu'est-ce qu'une perte de connaissance ?","a3":"C'est lorsque la victime ne répond pas et ne réagit pas, mais respire.","explain3":"Perte de connaissance (respire) → PLS. Arrêt cardiaque (ne respire plus) → RCP. Confondre les deux peut être fatal."},
  {"id":"07","type1":"VI","q1":"Vérifiez la présence du gilet de haute visibilité.","a1":"Indiquer où se trouve le gilet dans le véhicule, sans obligation de le sortir.","explain1":"Le gilet doit être accessible depuis l'intérieur (pas dans le coffre) pour le mettre AVANT de sortir du véhicule.","photo1":"gilet-haute-visibilite.jpg","q2":"En cas de panne ou d'accident, quel autre accessoire de sécurité est obligatoire ?","a2":"Le triangle de pré-signalisation.","explain2":"Ces deux équipements sont obligatoires depuis 2008. Sur autoroute, le triangle ne doit PAS être placé (trop dangereux).","q3":"Si un dégagement d'urgence de la victime est nécessaire, où doit-elle être déplacée ?","a3":"Dans un endroit suffisamment éloigné du danger et de ses conséquences.","explain3":"Le dégagement n'est justifié que si le danger est RÉEL, IMMÉDIAT et NON CONTRÔLABLE. Sinon, ne pas bouger la victime."},
  {"id":"08","type1":"VE","q1":"Montrez où s'effectue le contrôle du niveau du liquide de frein.","a1":"Ouvrir le capot et montrer le bocal de liquide de frein (petit réservoir transparent avec repères MIN/MAX).","explain1":"Niveau trop bas = fuite ou usure des plaquettes. Un circuit vide en roulant = pédale qui 'tombe dans le plancher'.","photo1":"bocal-liquide-frein.jpg","q2":"Quelle est la conséquence d'un niveau insuffisant du liquide de frein ?","a2":"Une perte d'efficacité du freinage.","explain2":"Si le niveau baisse à cause d'une fuite, le freinage peut devenir quasi nul en quelques appuis. Urgence absolue.","q3":"En cas de panne ou d'accident, quel équipement de sécurité doit être porté avant de quitter le véhicule ?","a3":"Le gilet de haute visibilité.","explain3":"La majorité des piétons tués sur route la nuit l'étaient faute de visibilité. Le gilet multiplie la distance de détection par 3 à 4."},
  {"id":"09","type1":"VI","q1":"Vérifiez la présence du certificat d'immatriculation du véhicule (ou carte grise).","a1":"Montrer le certificat d'immatriculation. La photocopie est acceptée.","explain1":"Depuis 2017, le certificat peut être présenté en version numérique (app ANTS). La photocopie est acceptée depuis 2013.","photo1":"carte-grise.jpg","q2":"Quels sont les deux autres documents obligatoires à présenter en cas de contrôle par les forces de l'ordre ?","a2":"L'attestation d'assurance et le permis de conduire.","explain2":"3 documents : carte grise + attestation assurance + permis. Sans assurance = 3 750€ d'amende + suspension possible.","requiredCount2":2,"q3":"Pourquoi l'alerte auprès des services de secours doit-elle être rapide et précise ?","a3":"Pour permettre aux services de secours d'apporter les moyens adaptés aux victimes dans le délai le plus court.","explain3":"Pour un arrêt cardiaque, chaque minute sans défibrillation = -10% de chances de survie. La précision détermine les moyens envoyés."},
  {"id":"10","type1":"VE","q1":"Contrôlez l'état de tous les balais d'essuie-glace du véhicule.","a1":"Inspecter visuellement les balais : en bon état, sans craquelure ni déformation du caoutchouc.","explain1":"Soulever le bras et faire glisser le caoutchouc entre les doigts. Un balai usé laisse des zones non essuyées = danger.","photo1":"balais-essuie-glace.jpg","q2":"Quel est le risque de circuler avec des balais d'essuie-glace défectueux ?","a2":"Une mauvaise visibilité en cas d'intempéries.","explain2":"Par pluie forte, des balais défectueux réduisent la visibilité à quelques mètres. Pénalisé au contrôle technique.","q3":"Quels sont les numéros d'urgence à composer ?","a3":"18 (pompiers), 15 (SAMU), 112 (numéro européen valable dans toute l'UE).","explain3":"Le 112 fonctionne sans crédit, sans code PIN, depuis n'importe quel réseau mobile en Europe. À retenir absolument."},
  {"id":"11","type1":"VI","q1":"Montrez l'indicateur de niveau de carburant.","a1":"Montrer la jauge de carburant sur le tableau de bord (aiguille entre E et F, ou affichage numérique).","explain1":"La flèche à côté du symbole pompe indique de quel côté est le bouchon du réservoir — utile à la station-service !","photo1":"jauge-carburant.jpg","q2":"Quelles sont les précautions à prendre lors du remplissage du réservoir ?","a2":"Arrêter le moteur, ne pas fumer, ne pas téléphoner.","explain2":"Les vapeurs d'essence sont très inflammables. Une étincelle de téléphone ou décharge statique peut déclencher un incendie.","q3":"Quels comportements adopter en présence d'une victime qui ne répond pas et ne réagit pas, mais respire ?","a3":"La placer en Position Latérale de Sécurité (PLS), alerter les secours, surveiller la respiration jusqu'à leur arrivée.","explain3":"La PLS évite que la victime s'étouffe avec sa langue ou ses vomissements. Face légèrement vers le bas, bouche vers le sol."},
  {"id":"12","type1":"VE","q1":"Montrez où s'effectue le remplissage du liquide de refroidissement.","a1":"Ouvrir le capot et montrer le bocal de liquide de refroidissement (transparent avec repères MIN/MAX).","explain1":"Ne JAMAIS ouvrir ce bocal moteur chaud : la pression projetterait du liquide bouillant. Attendre que le moteur soit froid.","photo1":"bocal-refroidissement.jpg","q2":"Quel est le danger si l'on complète le niveau du liquide lorsque le moteur est chaud ?","a2":"Un risque de brûlure.","explain2":"Le liquide est à plus de 90°C sous pression. L'ouverture du bouchon provoque une décompression violente sur le visage et les mains.","q3":"Comment arrêter une hémorragie ?","a3":"En appuyant fortement sur l'endroit qui saigne avec les doigts ou la paume de la main, en mettant un tissu propre sur la plaie.","explain3":"Compression directe = seul geste efficace immédiatement. Maintenir sans relâcher. Ne pas retirer le tissu s'il se gorge : en ajouter un par-dessus."},
  {"id":"13","type1":"VI","q1":"Actionnez le dégivrage de la lunette arrière et montrez le voyant ou le repère correspondant.","a1":"Appuyer sur le bouton de dégivrage lunette arrière (symbole rectangle + lignes horizontales) et montrer le voyant allumé.","explain1":"Des filaments conducteurs dans la vitre chauffent pour éliminer le givre. La lunette doit être entièrement dégagée avant de rouler.","photo1":"degivrage-lunette.jpg","q2":"Quelle peut être la conséquence d'une panne de dégivrage de la lunette arrière ?","a2":"Une insuffisance ou une absence de visibilité vers l'arrière.","explain2":"En hiver sans dégivrage, le rétroviseur intérieur est inutilisable. Risque accru lors des manœuvres et changements de voie.","q3":"Hors autoroute, en cas de panne ou d'accident, où doit être placé le triangle de pré-signalisation ?","a3":"À environ 30 m de la panne ou de l'accident, ou avant un virage, ou avant un sommet de côte.","explain3":"Sur autoroute, ne JAMAIS placer le triangle — trop dangereux. 30 m = environ 10 grandes enjambées. Toujours gilet AVANT de sortir."},
  {"id":"14","type1":"VE","q1":"Contrôlez l'état, la propreté et le fonctionnement de tous les clignotants côté trottoir.","a1":"Vérification des clignotants avant, latéral et arrière côté trottoir : propres, en bon état et fonctionnant. Toute anomalie signalée.","explain1":"Pour vérifier seul : activer les clignotants et faire le tour. Ou observer le reflet dans une vitrine.","photo1":"clignotants.jpg","q2":"Quelle est la signification d'un clignotement plus rapide que d'habitude ?","a2":"Non-fonctionnement de l'une des ampoules.","explain2":"Le système accélère le clignotement pour alerter le conducteur. À corriger rapidement : les autres usagers ne voient plus les intentions.","q3":"Quelles sont les conditions pour réaliser le dégagement d'urgence d'une victime ?","a3":"La victime doit être visible, facile à atteindre, rien ne doit gêner son dégagement, et on doit être sûr de pouvoir le réaliser.","explain3":"Le dégagement ne se justifie QUE si le danger est réel, immédiat et non contrôlable (ex : incendie). Sinon, ne pas bouger la victime."},
  {"id":"15","type1":"VI","q1":"Montrez le voyant d'alerte signalant une pression insuffisante d'huile dans le moteur.","a1":"Montrer le voyant en forme de lampe à huile (icône rouge) sur le tableau de bord.","explain1":"Ce voyant rouge est critique. S'il s'allume en roulant → arrêter IMMÉDIATEMENT le moteur. Continuer = destruction moteur en quelques minutes.","photo1":"voyant-huile.jpg","q2":"Quelles sont les conditions à respecter pour contrôler le niveau d'huile ?","a2":"Moteur froid et sur un terrain plat.","explain2":"Moteur chaud = huile dilatée, niveau faussé. En pente, l'huile se répartit inégalement dans le carter = lecture erronée.","q3":"Quelles sont les trois informations à transmettre aux services de secours ?","a3":"Le numéro de téléphone depuis lequel l'appel est émis, la nature du problème, et la localisation la plus précise possible.","explain3":"Mémo : QUI (numéro), QUOI (nature), OÙ (localisation). Ces 3 infos permettent d'envoyer les bons moyens au bon endroit.","requiredCount3":3},
  {"id":"16","type1":"VE","q1":"Contrôlez l'état, la propreté et le fonctionnement du ou des feux de brouillard arrière.","a1":"Vérification des feux de brouillard arrière : propres, en bon état et fonctionnant. Toute anomalie signalée.","explain1":"Ces feux rouges très lumineux améliorent la visibilité arrière dans le brouillard. En dehors, ils éblouissent les autres.","photo1":"feux-brouillard-arriere.jpg","q2":"Dans quels cas utilise-t-on les feux de brouillard arrière ?","a2":"Par temps de brouillard et neige.","explain2":"Uniquement quand la visibilité est inférieure à 50 m. Les utiliser par beau temps = risque d'éblouissement + amende.","q3":"Par quels moyens doit être réalisée l'alerte des secours ?","a3":"À l'aide d'un téléphone portable ou, à défaut, d'un téléphone fixe ou d'une borne d'appel d'urgence.","explain3":"Les bornes d'appel sur autoroute (toutes les 2 km) sont gratuites, localisées automatiquement et prioritaires sur le réseau."},
  {"id":"17","type1":"VI","q1":"Vérifiez la présence de l'éthylotest.","a1":"Montrer l'éthylotest présent dans le véhicule (obligatoire, généralement dans la boîte à gants).","explain1":"Obligatoire depuis 2012. L'éthylotest chimique ou électronique permet de contrôler son propre taux d'alcoolémie avant de conduire.","photo1":"ethylotest.jpg","q2":"A partir de quel taux d'alcoolémie, en période de permis probatoire, est-on en infraction ?","a2":"0,2 g/l — c'est-à-dire 0 verre, car dès le 1er verre ce seuil peut être dépassé.","explain2":"Pour les permis probatoires : seuil 0,2 g/l (quasi-zéro). Pour les permis classiques : 0,5 g/l. Un seul verre = risque réel.","q3":"Quel comportement doit-on adopter en présence d'une victime en arrêt cardiaque ?","a3":"ALERTER : alerter immédiatement les secours. MASSER : réanimation cardio-pulmonaire. DÉFIBRILLER : utiliser un DAE si possible.","explain3":"Mémo AMD (Alerter, Masser, Défibriller). Chaque minute sans RCP = -10% de survie. Ne pas attendre les secours pour commencer."},
  {"id":"18","type1":"VE","q1":"Contrôlez l'état, la propreté et le fonctionnement des feux de détresse à l'avant et à l'arrière.","a1":"Vérification des feux de détresse : propres, en bon état et fonctionnant. Toute anomalie signalée.","explain1":"Les feux de détresse (tous les clignotants simultanément) signalent un danger ou une immobilisation soudaine.","photo1":"feux-detresse.jpg","q2":"Dans quels cas doit-on utiliser les feux de détresse ?","a2":"En cas de panne, d'accident ou de ralentissement important.","explain2":"Utile aussi sur autoroute pour avertir les véhicules suivants d'un bouchon soudain. Ne pas oublier d'éteindre après.","q3":"Dans quel cas peut-on positionner une victime en Position Latérale de Sécurité (PLS) ?","a3":"Si la victime ne répond pas, ne réagit pas et respire.","explain3":"La PLS = inconsciente MAIS respire. Si elle ne respire plus → RCP. Si elle est consciente → ne pas la déplacer (blessures possibles)."},
  {"id":"19","type1":"VI","q1":"Montrez la commande de réglage du volant.","a1":"Montrer l'emplacement de la commande de réglage du volant (déverrouillage/réglage, généralement levier sous le volant).","explain1":"Bien régler le volant = posture correcte, accès aux commandes, visibilité du tableau de bord, et airbag efficace en cas de choc.","photo1":"reglage-volant.jpg","q2":"Pourquoi est-il important de bien régler son volant ? Citez deux exemples.","a2":"Confort de conduite, accessibilité aux commandes, visibilité du tableau de bord, efficacité des airbags.","explain2":"Un volant trop proche ou trop loin crée fatigue et réflexes plus lents. L'airbag est conçu pour une distance volant-conducteur précise.","requiredCount2":2,"q3":"Dans quelle situation peut-on déplacer une victime ?","a3":"En présence d'un danger réel, immédiat et non contrôlable. Le déplacement doit rester exceptionnel.","explain3":"Déplacer une victime avec fracture cervicale non détectée peut provoquer une tétraplégie. Ne bouger que si danger vital immédiat."},
  {"id":"20","type1":"VE","q1":"Contrôlez l'état, la propreté et le fonctionnement des feux de route.","a1":"Vérification des feux de route : propres, en bon état et fonctionnant. Toute anomalie signalée.","explain1":"Les feux de route éclairent jusqu'à 100 m (vs 50 m pour les feux de croisement). Obligatoire de les passer en croisement.","photo1":"feux-route.jpg","q2":"Citez un cas d'utilisation de l'appel lumineux.","a2":"Pour avertir de son approche, en cas de danger, ou à la place de l'avertisseur sonore.","explain2":"L'appel lumineux est plus discret et socialement accepté que le klaxon. En agglomération, le klaxon est interdit sauf danger immédiat.","requiredCount2":1,"q3":"En cas de panne ou d'accident, quel équipement de sécurité doit être porté avant de quitter le véhicule ?","a3":"Le gilet de haute visibilité.","explain3":"Porter le gilet AVANT de sortir du véhicule, même sur le bord d'une route tranquille. Le réflexe peut sauver la vie."},
  {"id":"21","type1":"VI","q1":"Positionnez la commande pour diriger l'air vers le pare-brise.","a1":"Orienter le sélecteur de ventilation vers l'icône pare-brise (dégivrage/désembuage).","explain1":"La position 'pare-brise' concentre l'air chaud sur la vitre pour désembuer rapidement. Astuce : combiner avec la clim pour un air sec.","photo1":"ventilation-pare-brise.jpg","q2":"Citez deux éléments complémentaires permettant un désembuage efficace.","a2":"La commande de vitesse de ventilation, la commande d'air chaud, et la climatisation.","explain2":"La clim assèche l'air et accélère drastiquement le désembuage même en hiver. Contre-intuitif mais très efficace.","requiredCount2":2,"q3":"Quel est l'objectif du Signal d'Alerte et d'Information des Populations (SAIP) ?","a3":"Avertir la population d'un danger imminent ou qu'un événement grave est en train de se produire.","explain3":"Le SAIP remplace les vieilles sirènes de la Guerre froide. Il peut aussi envoyer des notifications push via l'application dédiée."},
  {"id":"22","type1":"VE","q1":"Montrez où doit s'effectuer le contrôle du niveau d'huile moteur.","a1":"Le candidat montre la jauge. Pas de manipulation exigée. Si besoin, l'accompagnateur peut indiquer comment ouvrir le capot.","explain1":"La jauge d'huile (tige MIN/MAX) se lit moteur froid et sur terrain plat. Un niveau bas risque la casse moteur immédiate.","photo1":"jauge-huile-moteur.jpg","q2":"Quel est le principal risque d'un manque d'huile moteur ?","a2":"Un risque de détérioration ou de casse du moteur.","explain2":"L'huile lubrifie toutes les pièces métalliques en mouvement. Sans elle, les frottements provoquent une surchauffe et destruction rapide.","q3":"Comment est diffusée l'alerte émise par le Signal d'Alerte et d'Information aux Populations (SAIP) ?","a3":"Grâce aux sirènes, aux médias tels que Radio France et France Télévision ou encore grâce à l'application SAIP.","explain3":"Le SAIP utilise plusieurs canaux simultanément pour toucher le maximum de personnes. L'application envoie aussi des notifications push."},
  {"id":"23","type1":"VI","q1":"Montrez le voyant d'alerte signalant un défaut de batterie.","a1":"Montrer le voyant de charge batterie (icône batterie ou alternateur, généralement rouge) sur le tableau de bord.","explain1":"Ce voyant signale que l'alternateur ne recharge plus la batterie. S'il reste allumé en roulant, la batterie se décharge et la panne est imminente.","photo1":"voyant-batterie.jpg","q2":"Qu'est-ce qui peut provoquer la décharge de la batterie, moteur éteint ?","a2":"Les feux ou accessoires électriques en fonctionnement.","explain2":"Laisser des phares ou accessoires allumés moteur éteint vide la batterie sans qu'elle puisse se recharger. Risque de panne au démarrage.","q3":"A partir de quel âge peut-on suivre une formation aux premiers secours ?","a3":"A partir de 10 ans.","explain3":"Les gestes de premiers secours s'apprennent dès l'enfance. Former les jeunes crée des citoyens capables d'agir face à une urgence."},
  {"id":"24","type1":"VE","q1":"Montrez l'emplacement de la batterie du véhicule.","a1":"Le candidat montre l'emplacement de la batterie (généralement sous le capot). Si besoin, l'accompagnateur peut indiquer comment ouvrir le capot.","explain1":"La batterie alimente tous les systèmes électriques. Connaître son emplacement est nécessaire pour une recharge ou un démarrage assisté.","photo1":"batterie-emplacement.jpg","q2":"Quelle est la solution en cas de panne de batterie pour démarrer le véhicule sans le déplacer ?","a2":"Brancher une deuxième batterie en parallèle (ou les \"+\" ensemble et les \"-\" ensemble) ou la remplacer.","explain2":"Le branchement en parallèle fournit l'énergie nécessaire au démarrage. L'ordre des câbles est important pour éviter les courts-circuits.","q3":"Pourquoi faut-il pratiquer immédiatement une réanimation cardio-pulmonaire sur une victime en arrêt cardiaque ?","a3":"Car les lésions du cerveau surviennent dès les premières minutes.","explain3":"Sans oxygène, les cellules cérébrales meurent en 4 à 6 minutes. Chaque minute de RCP augmente les chances de survie sans séquelles."},
  {"id":"25","type1":"VI","q1":"De quelle couleur est le voyant qui indique une défaillance du système de freinage ?","a1":"Le voyant de défaillance du système de freinage est de couleur rouge.","explain1":"Un voyant rouge de freinage allumé en roulant est une urgence absolue : s'arrêter prudemment. Cela peut signaler une fuite ou une défaillance grave.","photo1":"voyant-frein.jpg","q2":"Quel est le risque de circuler avec un frein de parking mal desserré ?","a2":"Une dégradation du système de freinage.","explain2":"Le frein de parking applique en permanence les garnitures sur les disques ou tambours. La friction constante les use et chauffe dangereusement.","q3":"Hors autoroute ou endroit dangereux, en cas de panne ou d'accident, où doit être placé le triangle de pré-signalisation ?","a3":"Le triangle de pré-signalisation doit être placé à une distance d'environ 30 m de la panne ou de l'accident, ou avant un virage, ou un sommet de côte.","explain3":"30 m laisse le temps aux conducteurs arrivant de freiner avant le danger. Toujours mettre le gilet avant de sortir du véhicule."},
  {"id":"26","type1":"VE","q1":"Contrôlez l'état, la propreté et le fonctionnement des feux de croisement.","a1":"Vérification des feux de croisement : propres, en bon état et fonctionnant. Toute anomalie signalée.","explain1":"Les feux de croisement éclairent 50 m devant et s'inclinent vers le bas pour ne pas éblouir. À utiliser dès la tombée de la nuit.","photo1":"feux-croisement.jpg","q2":"Quelles sont les conséquences d'un mauvais réglage de ces feux ?","a2":"Une mauvaise vision vers l'avant et un risque d'éblouissement des autres usagers.","explain2":"Des feux trop hauts = éblouissement systématique. Trop bas = visibilité insuffisante. Réglage à revoir après un chargement lourd.","q3":"Dans quelle situation peut-on déplacer une victime ?","a3":"En présence d'un danger réel, immédiat et non contrôlable. Le déplacement doit rester exceptionnel.","explain3":"Un mouvement brusque peut transformer une fracture vertébrale en tétraplégie. Ne déplacer que si danger vital immédiat."},
  {"id":"27","type1":"VI","q1":"Montrez le voyant d'alerte signalant une température trop élevée du liquide de refroidissement.","a1":"Montrer le voyant de température du liquide de refroidissement (icône thermomètre dans le liquide, généralement rouge) sur le tableau de bord.","explain1":"Si ce voyant s'allume en roulant, arrêter le moteur dès que possible. Continuer = surchauffe et destruction moteur garanties.","photo1":"voyant-temperature-refroidissement.jpg","q2":"Quelle est la conséquence d'une température trop élevée de ce liquide ?","a2":"Une surchauffe ou une casse moteur.","explain2":"Le liquide de refroidissement dissipe la chaleur du moteur. S'il ne remplit plus ce rôle, les pièces métalliques se dilatent et se grippent.","q3":"Lors d'un appel avec les services de secours, pourquoi devez-vous attendre que votre correspondant vous autorise à raccrocher ?","a3":"Car il peut nous conseiller ou nous guider dans la réalisation des gestes à faire, ou ne pas faire, jusqu'à l'arrivée des secours.","explain3":"L'opérateur des secours peut transmettre des instructions vitales en temps réel. Raccrocher prématurément peut priver la victime d'aide cruciale."},
  {"id":"28","type1":"VE","q1":"Vérifiez l'état et la propreté des dispositifs réfléchissants.","a1":"Vérification des dispositifs réfléchissants : propres et en bon état (toute anomalie doit être signalée).","explain1":"Les dispositifs réfléchissants renvoient la lumière des phares des autres véhicules. Un réflecteur sale ou cassé réduit la visibilité du véhicule la nuit.","photo1":"dispositifs-reflechissants.jpg","q2":"Quelle est l'utilité des dispositifs réfléchissants ?","a2":"Rendre visible le véhicule la nuit.","explain2":"Contrairement aux feux actifs, les réflecteurs fonctionnent sans électricité. Ils sont essentiels si les feux tombent en panne.","q3":"A quel moment pouvez-vous mettre fin à un appel avec les secours ?","a3":"Uniquement lorsque notre correspondant nous invite à le faire.","explain3":"L'opérateur peut avoir besoin d'informations supplémentaires ou de guider les gestes de secours. Attendre son autorisation garantit une prise en charge complète."},
  {"id":"29","type1":"VI","q1":"Montrez le voyant signalant la mauvaise fermeture d'une portière.","a1":"Montrer le voyant de portière ouverte (icône voiture avec porte ouverte) sur le tableau de bord.","explain1":"Une portière mal fermée peut s'ouvrir en virage ou au freinage brusque. Le voyant permet de détecter ce danger avant de démarrer.","photo1":"voyant-portiere.jpg","q2":"Quelle précaution dois-je prendre pour que les enfants installés à l'arrière ne puissent pas ouvrir leur portière ?","a2":"Actionner la sécurité enfant sur les deux portières arrière.","explain2":"La sécurité enfant bloque l'ouverture de la portière de l'intérieur, empêchant un enfant d'ouvrir la portière pendant le trajet.","q3":"Citez les trois manières d'évaluer l'état de conscience d'une victime.","a3":"Lui poser des questions simples (\"comment ça va ?\"). Lui secouer doucement les épaules. Lui prendre la main en lui demandant d'exécuter un geste simple (\"serrez-moi la main\").","explain3":"Ces trois stimuli (verbal, physique, moteur) permettent d'évaluer progressivement le niveau de conscience et de décider du geste de secours adapté."},
  {"id":"30","type1":"VE","q1":"Contrôlez l'état, la propreté et le fonctionnement des feux de position à l'avant et à l'arrière du véhicule.","a1":"Vérification des feux de position : propres, en bon état et fonctionnant (toute anomalie doit être signalée).","explain1":"Les feux de position signalent la présence du véhicule à faible luminosité sans éclairage de route complet. Ils sont obligatoires dès la tombée du jour.","photo1":"feux-position.jpg","q2":"Par temps clair, à quelle distance doivent-ils être visibles ?","a2":"A 150 mètres.","explain2":"150 mètres de visibilité garantissent que les autres usagers peuvent anticiper la présence du véhicule. Cette norme est fixée par le code de la route.","q3":"Quels sont les risques pour une personne en perte de connaissance qui est allongée sur le dos ?","a3":"L'arrêt respiratoire et l'arrêt cardiaque.","explain3":"Sur le dos, la langue peut tomber en arrière et obstruer les voies aériennes. La PLS prévient ce risque en maintenant les voies dégagées."},
  {"id":"31","type1":"VI","q1":"Actionnez les feux de détresse.","a1":"Actionner le bouton de feux de détresse (losange rouge) : tous les clignotants clignotent simultanément.","explain1":"Le bouton de détresse est toujours un losange rouge, facilement identifiable même en urgence. Il doit fonctionner clé retirée.","photo1":"bouton-detresse.jpg","q2":"Quand les utilise-t-on ?","a2":"En cas de panne, d'accident ou de ralentissement important.","explain2":"Les feux de détresse avertissent les autres conducteurs d'un danger imprévu. Sur autoroute, ils signalent aussi les bouchons soudains.","q3":"Quels comportements adopter en cas de diffusion du signal d'alerte du Système d'Alerte et d'Information des Populations (SAIP) ?","a3":"Se mettre en sécurité. S'informer grâce aux médias et sites internet des autorités dès que leur consultation est possible. Respecter les consignes des autorités.","explain3":"Le SAIP est déclenché pour des dangers graves (catastrophe naturelle, attentat…). S'informer et obéir aux consignes des autorités est la réaction adaptée."},
  {"id":"32","type1":"VE","q1":"Sur le flanc d'un pneumatique, désignez le repère du témoin d'usure de la bande de roulement.","a1":"Désigner le triangle ou la mention TWI (Tread Wear Indicator) gravé sur le flanc, qui indique l'emplacement du témoin d'usure.","explain1":"Le témoin d'usure est une petite saillie dans les rainures. Quand la bande de roulement arrive à son niveau, le pneu est au minimum légal (1,6 mm) mais dangereux sur sol mouillé.","photo1":"temoin-usure-pneu.jpg","q2":"Qu'est-ce que l'aquaplanage, et quelle peut être sa conséquence ?","a2":"La présence d'un film d'eau entre le pneumatique et la chaussée pouvant entraîner une perte de contrôle du véhicule.","explain2":"Les rainures évacuent l'eau. Un pneu usé ne peut plus le faire efficacement : la roue se soulève et perd tout contact avec la chaussée.","q3":"Si un dégagement d'urgence de la victime est nécessaire, où doit-elle être déplacée ?","a3":"Dans un endroit suffisamment éloigné du danger et de ses conséquences.","explain3":"Le dégagement d'urgence ne se justifie qu'en présence d'un danger immédiat non maîtrisable. La victime doit être mise hors de portée du danger."},
  {"id":"33","type1":"VI","q1":"Montrez la commande permettant d'actionner le régulateur de vitesse.","a1":"Montrer la commande du régulateur de vitesse (généralement sur la colonne de direction ou le volant multifonction).","explain1":"Le régulateur de vitesse maintient une vitesse constante automatiquement. Connaître sa commande permet de l'activer et de le désactiver en toute sécurité.","photo1":"regulateur-vitesse.jpg","q2":"Sans actionner la commande du régulateur, comment le désactiver rapidement ?","a2":"En appuyant sur la pédale de frein ou d'embrayage.","explain2":"En situation d'urgence, l'action sur frein ou embrayage coupe immédiatement le régulateur. Cela permet de reprendre le contrôle de la vitesse sans chercher la commande.","q3":"Sur autoroute, comment indiquer avec précision les lieux de l'accident depuis un téléphone portable ?","a3":"En indiquant le numéro de l'autoroute, le sens de circulation et le point kilométrique.","explain3":"Le point kilométrique est indiqué sur des panneaux tous les kilomètres sur autoroute. Cette information permet aux secours d'intervenir directement au bon endroit."},
  {"id":"34","type1":"VE","q1":"Ouvrez la trappe à carburant et/ou vérifiez la bonne fermeture du bouchon.","a1":"Ouvrir la trappe à carburant (commande intérieure ou par pression) et vérifier que le bouchon est bien fermé et en bon état.","explain1":"Un bouchon de carburant mal fermé provoque des pertes par évaporation et peut constituer un risque d'incendie. La trappe doit se fermer hermétiquement.","photo1":"trappe-carburant.jpg","q2":"Quelles sont les précautions à prendre lors du remplissage du réservoir ?","a2":"Arrêter le moteur, ne pas fumer, ne pas téléphoner.","explain2":"Les vapeurs de carburant sont extrêmement inflammables. Moteur allumé, une étincelle ou une cigarette peuvent déclencher un incendie immédiat.","q3":"Pourquoi l'alerte auprès des services de secours doit-elle être rapide et précise ?","a3":"Pour permettre aux services de secours d'apporter les moyens adaptés aux victimes dans le délai le plus court.","explain3":"Chaque minute compte en situation d'urgence. Une alerte précise permet d'envoyer les bons secours (SAMU, pompiers) avec le bon matériel au bon endroit."},
  {"id":"35","type1":"VI","q1":"Sans l'actionner, montrez la commande de l'avertisseur sonore.","a1":"Montrer l'emplacement de la commande de l'avertisseur sonore (centre du volant ou bouton dédié).","explain1":"En situation de danger, trouver rapidement le klaxon sans regarder est essentiel. La position centrale du volant est standard sur la plupart des véhicules.","photo1":"avertisseur-sonore.jpg","q2":"Dans quel cas peut-on utiliser l'avertisseur sonore en agglomération ?","a2":"En cas de danger immédiat.","explain2":"En agglomération, le klaxon est réservé aux dangers imminents (piéton qui traverse soudainement, risque de collision). Son usage abusif est sanctionné.","q3":"Pourquoi ne faut-il pas laisser une personne en perte de connaissance allongée sur le dos ?","a3":"Car elle risque un étouffement par des liquides présents dans la gorge ou par la chute de la langue en arrière.","explain3":"Sur le dos, la langue et les sécrétions obstruent les voies aériennes. La PLS (sur le côté) maintient les voies dégagées et prévient l'asphyxie."},
  {"id":"36","type1":"VE","q1":"Montrez où s'effectue le remplissage de l'huile moteur.","a1":"Le candidat montre le bouchon de remplissage d'huile moteur. Si besoin, l'accompagnateur peut indiquer comment ouvrir le capot.","explain1":"Le bouchon de remplissage porte souvent le symbole d'une huilière. Ne pas confondre avec la jauge (qui mesure) : ce bouchon sert uniquement à ajouter de l'huile.","photo1":"bouchon-huile.jpg","q2":"Quel est le risque d'un manque d'huile moteur ?","a2":"Un risque de détérioration ou de casse du moteur.","explain2":"L'huile assure lubrification, refroidissement et protection des pièces. Un moteur tournant sans huile suffisante se détruit en quelques minutes.","q3":"L'utilisation d'un Défibrillateur Automatisé (DAE) sur une victime qui n'est pas en arrêt cardiaque présente-t-elle un risque ?","a3":"Non, car le défibrillateur se déclenche uniquement quand la victime est en arrêt cardiaque.","explain3":"Le DAE analyse lui-même le rythme cardiaque et ne délivre un choc que si nécessaire. Il est sans danger pour une victime au cœur battant."},
  {"id":"37","type1":"VI","q1":"Montrez la commande permettant de désactiver l'airbag du passager avant.","a1":"Montrer la commande de désactivation de l'airbag passager (généralement par clé ou bouton, souvent côté passager ou tableau de bord).","explain1":"L'airbag avant peut blesser grièvement un enfant en siège dos à la route. Sa désactivation est obligatoire dans ce cas pour éviter le choc du déploiement.","photo1":"airbag-passager.jpg","q2":"Dans quelle situation doit-on le désactiver ?","a2":"Lors du transport d'un enfant à l'avant dans un siège auto, dos à la route.","explain2":"Un siège dos à la route positionne la tête de l'enfant à quelques centimètres de l'airbag. En cas de déclenchement, l'impact peut être fatal.","q3":"Quelles sont les conditions pour réaliser le dégagement d'urgence d'une victime en présence d'un danger réel, immédiat et non contrôlable ?","a3":"La victime doit être visible, facile à atteindre et rien ne doit gêner son dégagement. Il faut être sûr de pouvoir réaliser le dégagement de la victime.","explain3":"Le dégagement d'urgence comporte des risques pour la victime et le sauveteur. Il ne se justifie que si le danger (incendie, noyade...) est certain et immédiat."},
  {"id":"38","type1":"VE","q1":"A l'aide de la plaque indicative, donnez la pression préconisée pour les pneumatiques arrières, véhicule chargé.","a1":"Lire la pression indiquée sur la plaque (généralement sur le montant de la portière conducteur) pour les pneus arrière en charge.","explain1":"La pression recommandée varie selon l'essieu et la charge. Sous-gonfler les pneus arrière d'un véhicule chargé augmente l'usure et les risques de crevaison.","photo1":"plaque-pressions.jpg","q2":"A quelle fréquence est-il préconisé de vérifier la pression des pneus ?","a2":"Chaque mois, pour une utilisation normale de son véhicule, et avant chaque long trajet.","explain2":"La pression diminue naturellement avec le temps et les variations de température. Une vérification mensuelle permet de maintenir le niveau correct.","q3":"Comment et pourquoi protéger une zone de danger en cas d'accident de la route ?","a3":"En délimitant clairement et largement la zone de danger de façon visible pour protéger les victimes et éviter un sur-accident.","explain3":"Le sur-accident est une cause fréquente de victimes supplémentaires. Baliser tôt et visiblement protège les victimes et les secouristes."},
  {"id":"39","type1":"VI","q1":"Montrez le voyant signalant l'absence de bouclage de la ceinture de sécurité du conducteur.","a1":"Montrer le voyant de ceinture non bouclée (icône personne avec ceinture barrée, généralement rouge ou orange) sur le tableau de bord.","explain1":"Ce voyant rappelle de boucler la ceinture avant de partir. La ceinture est le premier équipement de sécurité passive : son port réduit le risque de mort par 2 en cas d'accident.","photo1":"voyant-ceinture.jpg","q2":"En règle générale, à partir de quel âge un enfant peut-il être installé sur le siège passager avant du véhicule ?","a2":"10 ans.","explain2":"Avant 10 ans, les enfants doivent être attachés à l'arrière avec un dispositif adapté à leur taille. À l'avant, l'airbag représente un danger supplémentaire.","q3":"Comment est composé le signal d'alerte du Système d'Alerte et d'Information des Populations (SAIP) diffusé par les sirènes ?","a3":"Il se compose de deux codes distincts : le Signal National d'Alerte (SNA), variation du signal sur trois cycles successifs, et le signal de fin d'alerte, signal continu.","explain3":"Le signal modulé (montée/descente) signifie danger en cours. Le signal continu signifie fin d'alerte. Distinguer les deux évite panique inutile ou complacency dangereuse."},
  {"id":"40","type1":"VE","q1":"Vérifiez le fonctionnement de l'éclairage de la plaque d'immatriculation à l'arrière.","a1":"Allumer les phares et vérifier que la plaque d'immatriculation arrière est entièrement éclairée. Toute anomalie doit être signalée.","explain1":"L'éclairage de plaque est obligatoire la nuit. Une plaque non éclairée rend le véhicule plus difficile à identifier et constitue une infraction.","photo1":"eclairage-plaque.jpg","q2":"Un défaut d'éclairage de la plaque lors du contrôle technique entraîne-t-il une contre-visite ?","a2":"Oui.","explain2":"L'éclairage de plaque fait partie des points contrôlés au contrôle technique. Toute défaillance lumineuse entraîne une contre-visite obligatoire.","q3":"Quelles sont les trois informations à transmettre aux services de secours ?","a3":"Le numéro de téléphone à partir duquel l'appel est émis, la nature et la localisation la plus précise du problème.","explain3":"Ces trois informations permettent aux secours de rappeler si la communication est coupée, d'envoyer les bons moyens et de se rendre au bon endroit rapidement."},
  {"id":"41","type1":"VI","q1":"Vérifiez la présence de l'attestation d'assurance du véhicule et de sa vignette sur le pare-brise.","a1":"Montrer l'attestation d'assurance en cours de validité et sa vignette apposée sur le pare-brise côté conducteur.","explain1":"L'assurance RC est obligatoire. Circuler sans attestation valide constitue une infraction grave et peut engager ta responsabilité en cas d'accident.","q2":"Quels sont les deux autres documents obligatoires à présenter en cas de contrôle par les forces de l'ordre ?","a2":"Le certificat d'immatriculation et le permis de conduire. Le terme « carte grise » est accepté.","explain2":"Ces trois documents prouvent que tu es autorisé à conduire ce véhicule immatriculé et assuré. Leur absence peut entraîner immobilisation et amende.","requiredCount2":2,"q3":"Qu'est ce qu'une hémorragie ?","a3":"C'est une perte de sang prolongée qui ne s'arrête pas. Elle imbibe de sang un mouchoir en quelques secondes.","explain3":"Une hémorragie non contrôlée entraîne une chute de pression artérielle pouvant conduire au choc et à la mort. Comprimer immédiatement est vital."},
  {"id":"42","type1":"VE","q1":"Indiquez où se situe la sécurité enfant sur l'une des portières à l'arrière du véhicule.","a1":"Montrer le mécanisme de sécurité enfant situé sur le bord intérieur de la portière arrière, généralement un levier ou un interrupteur.","explain1":"Ce dispositif empêche l'ouverture de la portière depuis l'intérieur, évitant qu'un enfant ne l'ouvre accidentellement pendant le trajet.","q2":"Si la sécurité enfant est enclenchée, est-il possible d'ouvrir la portière arrière depuis l'extérieur ?","a2":"Oui.","explain2":"La sécurité enfant ne bloque que l'ouverture de l'intérieur. L'ouverture depuis l'extérieur reste possible pour permettre la sortie de l'enfant.","q3":"Quels sont les risques pour une personne victime d'une hémorragie ?","a3":"Entraîner pour la victime une détresse circulatoire ou un arrêt cardiaque.","explain3":"Une perte de sang importante réduit le volume sanguin circulant. Le cœur et le cerveau ne sont plus irrigués, pouvant causer l'arrêt cardiaque."},
  {"id":"43","type1":"VI","q1":"Allumez le(s) feu(x) de brouillard arrière(s) et montrez le voyant correspondant.","a1":"Actionner la commande des feux de brouillard arrière et montrer le voyant orange ou ambré s'allumant sur le tableau de bord.","explain1":"Le feu de brouillard arrière est visible jusqu'à 150 m dans le brouillard. Connaître son voyant évite de le laisser allumé par temps clair.","q2":"Pouvez-vous les utiliser par forte pluie ?","a2":"Non.","explain2":"Le feu antibrouillard arrière éblouit les conducteurs qui suivent par temps clair ou de pluie. Son usage est strictement réservé au brouillard dense.","q3":"Quels sont les signes d'un arrêt cardiaque ?","a3":"La victime ne répond pas, ne réagit pas et ne respire pas ou présente une respiration anormale.","explain3":"Ces trois critères permettent de reconnaître rapidement l'arrêt cardiaque et de déclencher les secours sans perdre de temps à chercher le pouls."},
  {"id":"44","type1":"VE","q1":"Avec l'assistance de l'accompagnateur, contrôlez l'état, la propreté et le fonctionnement du ou des feux de recul.","a1":"Vérification des feux de recul : propres, en bon état et qui fonctionnent (toute anomalie doit être signalée).","explain1":"Les feux de recul s'allument automatiquement en marche arrière. Ils éclairent la zone de recul et alertent les piétons de la manœuvre.","q2":"Quelles sont leurs deux utilités ?","a2":"Éclairer la zone de recul la nuit. Avertir les autres usagers de la manœuvre.","explain2":"Un feu de recul défaillant rend les manœuvres nocturnes dangereuses et prive les piétons d'un avertissement. C'est aussi un point de contrôle technique.","q3":"Qu'est ce qu'un défibrillateur automatisé externe (DAE) ?","a3":"C'est un appareil qui peut permettre de rétablir une activité cardiaque normale à une victime en arrêt cardiaque.","explain3":"Le DAE délivre un choc électrique pour resynchroniser le cœur en fibrillation. Il est accessible au public et guidé par des instructions vocales."},
  {"id":"45","type1":"VI","q1":"Montrez comment régler la hauteur de l'appui-tête du siège conducteur.","a1":"Montrer et actionner le mécanisme de réglage de l'appui-tête (bouton ou levier de déverrouillage) pour ajuster sa hauteur à la nuque.","explain1":"L'appui-tête doit être au niveau de la nuque, pas des épaules. Mal réglé, il n'offre aucune protection contre le coup du lapin en cas de choc arrière.","q2":"Quelle est son utilité ?","a2":"Permet de retenir le mouvement de la tête en cas de choc et de limiter les blessures.","explain2":"En cas de choc arrière, la tête part en hyperextension. L'appui-tête limite ce mouvement et réduit les lésions cervicales graves.","q3":"Par quels moyens doit être réalisée l'alerte des secours ?","a3":"L'alerte doit être donnée à l'aide d'un téléphone portable ou, à défaut, d'un téléphone fixe, ou d'une borne d'appel d'urgence.","explain3":"Alerter rapidement les secours est la priorité. Les bornes d'urgence sur autoroute permettent de localiser automatiquement l'appelant."},
  {"id":"46","type1":"VE","q1":"Avec l'assistance de l'accompagnateur, contrôlez l'état, la propreté et le fonctionnement des feux de stop.","a1":"Vérification des feux de stop : propres, en bon état et fonctionnent (toute anomalie doit être signalée).","explain1":"Les feux de stop préviennent les véhicules suiveurs d'un freinage. Un feu défaillant augmente le risque de collision arrière, surtout à vitesse élevée.","q2":"Quelle est la conséquence en cas de panne des feux de stop ?","a2":"Un manque d'information pour les usagers suiveurs et un risque de collision.","explain2":"Sans feux de stop, les conducteurs derrière ne peuvent pas anticiper ton freinage. Le risque de tamponnade est maximal sur autoroute ou route rapide.","q3":"Lors d'un appel avec les services de secours, pourquoi devez-vous attendre que votre correspondant vous autorise à raccrocher ?","a3":"Car il peut nous conseiller ou nous guider dans la réalisation des gestes à faire, ou ne pas faire, jusqu'à l'arrivée des secours.","explain3":"L'opérateur des secours peut donner des instructions vitales en temps réel. Raccrocher trop tôt prive la victime d'une assistance précieuse."},
  {"id":"47","type1":"VI","q1":"De quelle couleur est le voyant qui indique au conducteur que le feu de brouillard arrière est allumé ?","a1":"Le voyant du feu de brouillard arrière est de couleur orange (ambre).","explain1":"La couleur orange signale un élément actif non urgent. Connaître ce voyant permet de vérifier que le brouillard arrière est bien éteint hors brouillard.","q2":"Quelle est la différence entre un voyant orange et un voyant rouge ?","a2":"Rouge : une anomalie de fonctionnement ou un danger. Orange : un élément important.","explain2":"Un voyant rouge exige un arrêt immédiat du véhicule. Un voyant orange signale un point d'attention sans urgence absolue mais à ne pas ignorer.","q3":"Qu'est ce qu'un arrêt cardiaque ?","a3":"Le cœur ne fonctionne plus ou fonctionne d'une façon anarchique.","explain3":"Lors d'un arrêt cardiaque, le sang n'est plus pompé vers le cerveau. Sans geste de secours dans les 4 à 6 minutes, les lésions cérébrales deviennent irréversibles."},
  {"id":"48","type1":"VE","q1":"Ouvrez et refermez le capot, puis vérifiez sa bonne fermeture.","a1":"Ouvrir le capot avec la commande intérieure, puis le refermer fermement en appuyant jusqu'au double clic de verrouillage. Vérifier qu'il ne bouge plus.","explain1":"Un capot mal fermé peut s'ouvrir brusquement à grande vitesse, obstruant totalement la visibilité et provoquant un accident grave.","q2":"En roulant, quel est le risque d'une mauvaise fermeture du capot ?","a2":"Un risque d'ouverture du capot pouvant entraîner un accident.","explain2":"À vitesse élevée, la pression aérodynamique soulève le capot. S'il s'ouvre, toute visibilité est perdue instantanément, entraînant une perte de contrôle.","q3":"Quel est le risque principal d'un arrêt cardiaque sans intervention des secours ?","a3":"La mort de la victime qui survient en quelques minutes.","explain3":"Sans RCP, le cerveau est privé d'oxygène. Les dommages irréversibles apparaissent en 4 à 6 minutes. Chaque minute sans massage réduit la survie de 10%."},
  {"id":"49","type1":"VI","q1":"Montrez la commande de recyclage de l'air.","a1":"Montrer le bouton de recyclage de l'air (icône personne dans une boucle ou flèche circulaire) sur la commande de climatisation.","explain1":"Le recyclage coupe l'arrivée d'air extérieur. Il permet d'éviter les odeurs ou fumées en ville, mais provoque de la buée si maintenu trop longtemps.","q2":"Quel peut être le risque de maintenir le recyclage de l'air de manière prolongée ?","a2":"Un risque de mauvaise visibilité par l'apparition de buée sur les surfaces vitrées.","explain2":"Sans renouvellement d'air, l'humidité s'accumule dans l'habitacle. La buée réduit la visibilité et peut provoquer des erreurs d'appréciation.","q3":"Quels sont les risques pour une personne en perte de connaissance qui est allongée sur le dos ?","a3":"L'arrêt respiratoire et l'arrêt cardiaque.","explain3":"Sur le dos, la langue peut obstruer les voies aériennes. La PLS (position latérale de sécurité) maintient les voies dégagées et prévient l'asphyxie."},
  {"id":"50","type1":"VE","q1":"Montrez l'orifice de remplissage du produit lave-glace.","a1":"Montrer le bouchon du réservoir lave-glace (icône pare-brise avec jets d'eau) dans le compartiment moteur. Si nécessaire, l'accompagnateur peut indiquer comment ouvrir le capot.","explain1":"Un réservoir de lave-glace vide prive de visibilité lors de projections de boue ou sel. Localiser cet orifice permet de faire l'appoint facilement.","q2":"Quel est le principal risque d'une absence de liquide lave-glace ?","a2":"Une mauvaise visibilité.","explain2":"Sans lave-glace, les salissures s'accumulent sur le pare-brise lors d'éclaboussures. La vision est réduite en quelques secondes, créant un danger immédiat.","q3":"Pourquoi faut-il pratiquer immédiatement une réanimation cardio-pulmonaire sur une victime en arrêt cardiaque ?","a3":"Car les lésions du cerveau surviennent dès les premières minutes.","explain3":"Le cerveau tolère moins de 6 minutes sans oxygène. La RCP maintient une circulation minimale et double les chances de survie en attendant les secours."},
  {"id":"51","type1":"VI","q1":"Allumez les feux de route et montrez le voyant correspondant.","a1":"Actionner la commande des feux de route (plein phares) et montrer le voyant bleu s'allumant sur le tableau de bord.","explain1":"Le voyant bleu des feux de route rappelle qu'ils sont allumés. Il faut les éteindre dès qu'un véhicule arrive en face pour éviter l'éblouissement.","q2":"Quel est le risque de maintenir les feux de route lors d'un croisement avec d'autres usagers ?","a2":"Un risque d'éblouissement des autres usagers.","explain2":"Les feux de route éclairent 150 m mais éblouissent frontalement. L'éblouissement provoque une cécité momentanée pouvant durer plusieurs secondes.","q3":"Quel est l'objectif du Signal d'Alerte et d'Information des Populations (SAIP) ?","a3":"Avertir la population d'un danger imminent ou qu'un événement grave est en train de se produire.","explain3":"Le SAIP déclenche des sirènes pour alerter la population. Connaître son signal permet de réagir rapidement et de suivre les consignes des autorités."},
  {"id":"52","type1":"VE","q1":"Vérifiez l'état, la propreté et le fonctionnement des feux diurnes.","a1":"Vérification des feux diurnes : propres, en bon état et qui fonctionnent (toute anomalie doit être signalée).","explain1":"Les feux diurnes s'allument automatiquement. Ils améliorent la visibilité du véhicule le jour sans consommer autant que les feux de croisement.","q2":"Quelle est leur utilité ?","a2":"Rendre le véhicule plus visible le jour.","explain2":"Les études montrent que les feux diurnes réduisent les accidents frontaux. Ils signalent ta présence aux autres usagers même en plein jour.","q3":"A quel moment pouvez-vous mettre fin à un appel avec les secours ?","a3":"Uniquement lorsque notre correspondant nous invite à le faire.","explain3":"L'opérateur peut avoir besoin d'informations supplémentaires ou guider les gestes de secours en temps réel. Attendre sa permission garantit une prise en charge optimale."},
  {"id":"53","type1":"VI","q1":"Vérifiez la présence du constat amiable dans le véhicule.","a1":"Montrer le document constat amiable d'accident automobile rangé dans le véhicule, prêt à être utilisé.","explain1":"Le constat amiable permet de décrire les circonstances d'un accident entre conducteurs. L'avoir à portée évite les conflits et accélère l'indemnisation.","q2":"En cas d'accident, dans quel délai doit-il être transmis à l'assureur ?","a2":"5 jours.","explain2":"Passé ce délai, l'assureur peut contester la validité du constat. Envoyer rapidement protège tes droits à indemnisation.","q3":"Quel est le risque principal d'un arrêt cardiaque sans intervention des secours ?","a3":"La mort de la victime qui survient en quelques minutes.","explain3":"Chaque minute sans réanimation réduit les chances de survie d'environ 10%. Agir immédiatement est la seule façon de donner une chance à la victime."},
  {"id":"54","type1":"VE","q1":"Vérifiez la présence du triangle de pré-signalisation.","a1":"Montrer le triangle de pré-signalisation rangé dans le coffre ou son emplacement prévu dans le véhicule.","explain1":"Le triangle balise la zone de danger à 30 m du véhicule en panne hors agglomération. Son absence en cas de besoin aggrave le risque de sur-accident.","q2":"Utilise-t-on le triangle de pré-signalisation sur autoroute ?","a2":"Non.","explain2":"Sur autoroute, la vitesse des véhicules rend la pose du triangle extrêmement dangereuse. On utilise les feux de détresse et le gilet réfléchissant.","q3":"Quel comportement doit-on adopter en présence d'une victime en arrêt cardiaque ?","a3":"ALERTER : alerter immédiatement les secours. MASSER : pratiquer une réanimation cardio-pulmonaire. DEFIBRILLER : utiliser un défibrillateur automatique (DAE) si possible.","explain3":"La chaîne de survie (alerter, masser, défibriller) multiplie par 3 les chances de survie. Chaque maillon est indispensable pour maximiser les chances."},
  {"id":"55","type1":"VI","q1":"De quelle couleur est le voyant qui indique une défaillance du système de freinage.","a1":"Le voyant de défaillance du système de freinage est de couleur rouge.","explain1":"Un voyant rouge s'allumant pendant la conduite signale un danger immédiat. Pour les freins, cela impose un arrêt dès que possible en sécurité.","q2":"Quel est le risque de circuler avec un frein de parking mal desserré ?","a2":"Une dégradation du système de freinage.","explain2":"Le frein à main partiellement serré chauffe les disques et garnitures. Une surchauffe prolongée peut réduire l'efficacité des freins de manière permanente.","q3":"Comment arrêter une hémorragie ?","a3":"En appuyant fortement sur l'endroit qui saigne avec les doigts ou avec la paume de la main en mettant un tissu propre sur la plaie.","explain3":"La compression directe est le moyen le plus efficace d'arrêter un saignement. Elle réduit le flux sanguin et permet la coagulation sur la plaie."},
  {"id":"56","type1":"VE","q1":"Montrez où s'effectue le changement d'une ampoule à l'avant du véhicule.","a1":"Montrer l'emplacement des ampoules à l'avant (sous le capot, derrière le bloc optique). Si nécessaire, l'accompagnateur peut indiquer comment ouvrir le capot.","explain1":"Connaître l'emplacement des ampoules avant permet de les changer ou de les faire changer rapidement. Un feu défaillant est dangereux et contrôlé.","q2":"Quelles sont les conséquences en cas de panne d'un feu de croisement ?","a2":"Une mauvaise visibilité et le risque d'être confondu avec un deux roues.","explain2":"Avec un seul feu, les autres usagers peuvent confondre ta voiture avec une moto. Cette confusion peut entraîner des manœuvres de dépassement dangereuses.","q3":"Citez les trois manières d'évaluer l'état de conscience d'une victime ?","a3":"Lui poser des questions simples (\"comment ça va ?\", \"vous m'entendez ?\"). Lui secouer doucement les épaules. Lui prendre la main en lui demandant d'exécuter un geste simple (\"serrez-moi la main\").","explain3":"Ces trois stimuli (verbal, physique, moteur) permettent d'évaluer le niveau de conscience et d'orienter le geste de secours adapté sans perdre de temps.","requiredCount3":3},
  {"id":"57","type1":"VI","q1":"Si le véhicule en est équipé, montrez la commande du limiteur de vitesse.","a1":"Montrer la commande du limiteur de vitesse (généralement sur la colonne de direction ou le volant multifonction), si le véhicule en est équipé.","explain1":"Le limiteur empêche de dépasser la vitesse programmée sans la couper. Connaître sa commande permet de l'utiliser en zones à limitation stricte.","q2":"Quelle est l'utilité d'un limiteur de vitesse ?","a2":"Ne pas dépasser la vitesse programmée par le conducteur.","explain2":"Contrairement au régulateur, le limiteur laisse le conducteur maître de l'accélération mais bloque tout dépassement de la limite fixée.","q3":"Quels sont les numéros d'urgence à appeler ?","a3":"Le 18, numéro d'appel des sapeurs-pompiers. Le 15, numéro d'appel des SAMU. Le 112, numéro réservé aux appels d'urgence valide dans l'ensemble de l'Union Européenne.","explain3":"Mémoriser ces trois numéros permet d'appeler le bon service selon la nature de l'urgence. Le 112 fonctionne même sans crédit et dans toute l'Europe."},
  {"id":"58","type1":"VE","q1":"Montrez où s'effectue le changement d'une ampoule à l'arrière du véhicule.","a1":"Montrer l'emplacement des ampoules arrière (bloc optique arrière accessible depuis le coffre ou l'extérieur). Indiquer comment y accéder.","explain1":"Connaître l'accès aux blocs optiques arrière permet d'intervenir rapidement. Un feu arrière défaillant est dangereux la nuit et sanctionné au contrôle technique.","q2":"Quelles sont les conséquences en cas de panne d'un feu de position arrière ?","a2":"Être mal vu et un risque de collision.","explain2":"Un feu de position arrière en panne rend le véhicule quasi invisible la nuit pour les véhicules suiveurs, augmentant fortement le risque de collision arrière.","q3":"Comment est diffusée l'alerte émise par le Signal d'Alerte et d'Information aux Populations (SAIP) ?","a3":"Grâce aux sirènes, aux médias tels que Radio France et France Télévision ou encore grâce à l'application SAIP.","explain3":"La diversification des canaux garantit que l'alerte touche le maximum de personnes, y compris celles sans accès aux sirènes ou à internet."},
  {"id":"59","type1":"VI","q1":"Faites fonctionner l'essuie-glace arrière du véhicule.","a1":"Actionner la commande de l'essuie-glace arrière (généralement sur le combiné de colonne de direction) et vérifier son bon fonctionnement.","explain1":"L'essuie-glace arrière maintient la visibilité vers l'arrière par temps de pluie. Un essuie-glace défaillant rend les manœuvres et les rétroviseurs moins efficaces.","q2":"Pour une bonne visibilité vers l'arrière, en plus de l'utilisation de l'essuie-glace, quelle commande pouvez-vous actionner par temps de pluie ?","a2":"La commande de désembuage arrière. Le terme dégivrage peut remplacer celui de désembuage.","explain2":"Le désembuage arrière chauffe le lunette arrière via des filaments électriques. Combiné à l'essuie-glace, il garantit une visibilité optimale vers l'arrière.","q3":"Quels comportements adopter en présence d'une victime qui ne répond pas et ne réagit pas, mais respire ?","a3":"La placer en position latérale de sécurité. Alerter les secours. Surveiller la respiration de la victime jusqu'à l'arrivée des secours.","explain3":"La PLS protège les voies aériennes d'une personne inconsciente. La surveiller permet de détecter toute dégradation et d'informer les secours en temps réel."},
  {"id":"60","type1":"VE","q1":"Ouvrez et refermez le coffre, puis vérifiez sa bonne fermeture.","a1":"Ouvrir le coffre avec la commande prévue, puis le refermer fermement jusqu'au verrouillage. Vérifier qu'il ne bouge plus et qu'aucun voyant d'alerte ne reste allumé.","explain1":"Un coffre mal fermé peut s'ouvrir en route, masquant la visibilité arrière et dispersant potentiellement le chargement sur la chaussée.","q2":"Lorsque vous transportez un poids important dans le coffre, quelles sont les précautions à prendre en ce qui concerne les pneumatiques et l'éclairage avant ?","a2":"Augmenter la pression des pneumatiques et régler la hauteur des feux avants.","explain2":"Une charge lourde à l'arrière comprime les pneus et incline les feux vers le haut. Un sur-gonflage arrière et un réglage des feux évitent l'usure et l'éblouissement.","q3":"L'utilisation d'un Défibrillateur Automatisé (DAE) sur une victime qui n'est pas en arrêt cardiaque présente-t-elle un risque ?","a3":"Non car le défibrillateur se déclenche uniquement quand la victime est en arrêt cardiaque.","explain3":"Le DAE analyse automatiquement le rythme cardiaque avant tout choc. Il n'envoie aucun choc si le cœur fonctionne normalement, garantissant une sécurité totale."},
  {"id":"61","type1":"VI","q1":"Indiquez où se situent les attaches de type Isofix dans le véhicule.","a1":"Montrer les anneaux Isofix situés entre le dossier et l'assise des sièges arrière (obligatoires sur les véhicules neufs depuis 2011).","explain1":"L'Isofix est une fixation rigide pour sièges enfant. Plus sûr qu'une ceinture : il empêche le siège de bouger en cas de choc violent.","q2":"Peut-on fixer tous les sièges enfant sur des attaches de type Isofix ?","a2":"Non, uniquement ceux compatibles avec ce type d'attache.","explain2":"Chaque siège enfant précise sa compatibilité Isofix sur son étiquette. Monter un siège non compatible risque un mauvais ancrage dangereux.","q3":"Comment vérifier la respiration d'une victime ?","a3":"Regarder si le ventre et la poitrine se soulèvent, et sentir de l'air à l'expiration.","explain3":"Technique LVA : Voir, Écouter, Sentir pendant 10 secondes. Pas de respiration → appeler les secours et démarrer la RCP immédiatement."},
  {"id":"62","type1":"VE","q1":"Ouvrez et refermez le coffre, puis vérifiez sa bonne fermeture.","a1":"Ouvrir le coffre avec la commande prévue, puis le refermer fermement jusqu'au verrouillage. Vérifier qu'il ne bouge plus.","explain1":"Un coffre mal fermé peut s'ouvrir en route et masquer la visibilité arrière ou disperser le chargement sur la chaussée.","q2":"Quels sont les risques de circuler avec des objets sur la plage arrière ?","a2":"Une mauvaise visibilité vers l'arrière et un risque de projection en cas de freinage brusque ou de choc.","explain2":"Des objets en vrac sur la plage arrière deviennent des projectiles. Ils peuvent blesser les passagers ou obstruer la visibilité vers l'arrière.","q3":"Qu'est-ce qu'une hémorragie ?","a3":"C'est une perte de sang prolongée qui ne s'arrête pas. Elle imbibe de sang un mouchoir en quelques secondes.","explain3":"Une hémorragie non contrôlée entraîne un choc circulatoire en quelques minutes. Comprimer immédiatement est vital pour stopper le saignement."},
  {"id":"63","type1":"VI","q1":"Montrez sur le tableau de bord le voyant indiquant une baisse de pression d'air d'un pneumatique.","a1":"Montrer le voyant TPMS (icône pneu avec point d'exclamation). Obligatoire sur les véhicules neufs depuis novembre 2014.","explain1":"Ce voyant signale une pression trop basse avant que tu t'en aperçoives. Pneu sous-gonflé = consommation +10% et risque d'éclatement.","q2":"À quelle fréquence est-il préconisé de vérifier la pression d'air des pneumatiques ?","a2":"Tous les mois.","explain2":"La pression baisse naturellement d'environ 0,1 bar par mois. Une vérification mensuelle à froid évite usure prématurée et surconsommation.","q3":"Qu'est-ce qu'un arrêt cardiaque ?","a3":"Le cœur ne fonctionne plus ou fonctionne d'une façon anarchique.","explain3":"Lors d'un arrêt cardiaque, le sang n'est plus pompé vers le cerveau. Sans geste de secours en 4 à 6 minutes, les lésions deviennent irréversibles."},
  {"id":"64","type1":"VE","q1":"Procédez à l'ouverture du capot puis à sa fermeture en vous assurant de son verrouillage.","a1":"Tirer la commande intérieure du capot, déverrouiller la sécurité sous le capot, puis refermer fermement jusqu'au double clic.","explain1":"Un capot mal fermé s'ouvre à grande vitesse sous la pression aérodynamique, supprimant toute visibilité et provoquant un accident grave.","q2":"Pour un capot s'ouvrant depuis l'avant du véhicule, quelle est l'utilité du dispositif de sécurité ?","a2":"Empêcher l'ouverture du capot en circulation en cas de mauvais verrouillage.","explain2":"Ce double verrou évite qu'un premier verrouillage insuffisant conduise à une ouverture en roulant. C'est une sécurité passive indispensable.","q3":"Quels sont les risques pour une personne victime d'une hémorragie ?","a3":"Entraîner pour la victime une détresse circulatoire ou un arrêt cardiaque.","explain3":"Une perte de sang importante réduit le volume sanguin circulant. Le cœur et le cerveau ne sont plus irrigués, pouvant causer l'arrêt cardiaque."},
  {"id":"65","type1":"VI","q1":"Montrez la commande de réglage de hauteur des feux.","a1":"Dispositif situé en général à gauche du volant.","explain1":"Ce correcteur adapte l'angle des feux à la charge. Un véhicule chargé à l'arrière pointe les feux vers le haut : risque d'éblouir les autres.","q2":"Pourquoi doit-on régler la hauteur des feux ?","a2":"Pour ne pas éblouir les autres usagers.","explain2":"Un mauvais réglage réduit la visibilité des conducteurs en face. C'est aussi un point vérifié au contrôle technique.","q3":"Comment et pourquoi protéger une zone de danger en cas d'accident de la route ?","a3":"En délimitant clairement et largement la zone de danger de façon visible pour protéger les victimes et éviter un sur-accident.","explain3":"Le sur-accident est fréquent et mortel. Baliser large et tôt protège les victimes et les secouristes avant même les premiers gestes."},
  {"id":"66","type1":"VE","q1":"Montrez où se situent les gicleurs de lave-glace avant.","a1":"Indiquer les gicleurs sur le capot ou en bas du pare-brise selon le modèle. Les vérifier propres et non obturés.","explain1":"Des gicleurs bouchés ou mal orientés ne nettoient plus le pare-brise. Les vérifier régulièrement évite une perte de visibilité soudaine.","q2":"Quelle est la principale conséquence d'un dispositif de lave-glace défaillant ?","a2":"Une mauvaise visibilité due à l'impossibilité de nettoyer le pare-brise.","explain2":"Sans lave-glace fonctionnel, une projection de boue rend le pare-brise opaque en quelques secondes. Particulièrement dangereux derrière un camion.","q3":"Qu'est-ce qu'un défibrillateur automatisé externe (DAE) ?","a3":"C'est un appareil qui peut permettre de rétablir une activité cardiaque normale à une victime en arrêt cardiaque.","explain3":"Le DAE délivre un choc électrique pour resynchroniser le cœur. Il est guidé par instructions vocales et accessible au grand public."},
  {"id":"67","type1":"VI","q1":"Mettez le rétroviseur intérieur en position « nuit ».","a1":"Basculer la languette sous le rétroviseur, ou indiquer le système automatique de mise en position nuit si équipé.","explain1":"La position nuit incline le miroir pour renvoyer les phares arrière vers le bas. Sans ça, éblouissement à 90 km/h = 125 m à l'aveugle.","q2":"Quel est l'intérêt de la position nuit ?","a2":"Ne pas être ébloui par les feux du véhicule suiveur.","explain2":"L'éblouissement par l'arrière provoque 2 à 5 secondes de cécité temporaire. À 90 km/h, tu roules 125 m sans voir clairement.","q3":"Comment est composé le signal d'alerte du SAIP diffusé par les sirènes ?","a3":"Deux codes : le Signal National d'Alerte (SNA), variation sur 3 cycles successifs. Signal de fin d'alerte : signal continu.","explain3":"Signal modulé = danger en cours. Signal continu = fin d'alerte. Distinguer les deux évite panique inutile ou réaction insuffisante."},
  {"id":"68","type1":"VE","q1":"Contrôlez l'état du flanc sur l'un des pneumatiques.","a1":"Vérification visuelle du flanc : en bon état, sans coupure, boursouflure ni déformation. Toute anomalie doit être signalée.","explain1":"Le flanc est la partie la plus fragile du pneu, vulnérable aux chocs de trottoir. Une boursouflure signale un risque d'éclatement imminent.","q2":"Citez un endroit où l'on peut trouver les pressions préconisées pour les pneumatiques.","a2":"Sur une plaque sur une portière, dans la notice d'utilisation du véhicule, ou au niveau de la trappe à carburant.","explain2":"La pression varie selon l'essieu et la charge. Toujours vérifier à froid. Sous-gonflage = surchauffe et usure anormale des flancs.","q3":"Sur autoroute, comment indiquer avec précision les lieux d'un accident depuis un téléphone portable ?","a3":"En indiquant le numéro de l'autoroute, le sens de circulation et le point kilométrique.","explain3":"Les panneaux kilométriques sont présents tous les kilomètres sur autoroute. Cette info précise permet aux secours d'intervenir directement au bon endroit."},
  {"id":"69","type1":"VI","q1":"Faites fonctionner les essuie-glaces avants du véhicule sur la position la plus rapide.","a1":"Actionner le levier des essuie-glaces sur la colonne de direction et le placer sur la position la plus rapide.","explain1":"Les positions vont d'intermittent à rapide. En fortes pluies, la vitesse max est indispensable pour maintenir la visibilité.","q2":"Comment détecte-t-on leur usure en circulation ?","a2":"En cas de pluie, lorsqu'ils laissent des traces sur le pare-brise.","explain2":"Stries ou zones non essuyées signalent un caoutchouc durci. À changer avant l'hiver, au plus tard tous les 2 ans.","q3":"Comment vérifier la respiration d'une victime ?","a3":"Regarder si le ventre et la poitrine se soulèvent, et sentir de l'air à l'expiration.","explain3":"Technique LVA : Voir, Écouter, Sentir pendant 10 secondes. Si pas de respiration → appeler les secours et démarrer la RCP."},
  {"id":"70","type1":"VE","q1":"Montrez où s'effectue le contrôle du niveau du liquide de frein.","a1":"Ouvrir le capot et montrer le bocal de liquide de frein (petit réservoir transparent avec repères MIN/MAX).","explain1":"Un niveau bas peut signaler une fuite ou une usure des plaquettes. Circuit vide en roulant = pédale qui tombe dans le plancher.","q2":"Quelle est la conséquence d'un niveau insuffisant du liquide de frein ?","a2":"Une perte d'efficacité du freinage.","explain2":"Si le niveau baisse à cause d'une fuite, le freinage peut devenir quasi nul en quelques appuis. C'est une urgence absolue.","q3":"En cas de panne ou d'accident, quel équipement de sécurité doit être porté avant de quitter le véhicule ?","a3":"Le gilet de haute visibilité.","explain3":"Porter le gilet AVANT de sortir du véhicule, même sur une route tranquille. Il multiplie la distance à laquelle les autres te voient par 3 à 4."},
  {"id":"71","type1":"VI","q1":"Vérifiez la présence du gilet de haute visibilité.","a1":"Montrer où se trouve le gilet dans le véhicule, sans obligation de le sortir.","explain1":"Le gilet doit être accessible depuis l'intérieur (pas dans le coffre) pour le mettre AVANT de sortir. Ce réflexe peut sauver la vie.","q2":"En cas de panne ou d'accident, quel autre accessoire de sécurité est obligatoire ?","a2":"Le triangle de pré-signalisation.","explain2":"Ces deux équipements sont obligatoires depuis 2008. Sur autoroute, le triangle ne doit PAS être posé : trop dangereux à grande vitesse.","q3":"Si un dégagement d'urgence de la victime est nécessaire, où doit-elle être déplacée ?","a3":"Dans un endroit suffisamment éloigné du danger et de ses conséquences.","explain3":"Le dégagement n'est justifié que si le danger est réel, immédiat et non contrôlable. Sinon, ne pas bouger la victime : risque de tétraplégie."},
  {"id":"72","type1":"VE","q1":"Montrez où s'effectue le remplissage du liquide de refroidissement.","a1":"Ouvrir le capot et montrer le bocal de liquide de refroidissement (transparent avec repères MIN/MAX).","explain1":"Ne JAMAIS ouvrir ce bocal moteur chaud : la pression projette du liquide bouillant sur le visage et les mains. Attendre le refroidissement complet.","q2":"Quel est le danger si l'on complète le niveau du liquide lorsque le moteur est chaud ?","a2":"Un risque de brûlure.","explain2":"À plus de 90°C sous pression, l'ouverture du bouchon projette le liquide sur le visage et les mains. Les brûlures peuvent être très graves.","q3":"Comment arrêter une hémorragie ?","a3":"En appuyant fortement sur l'endroit qui saigne avec les doigts ou la paume de la main, en mettant un tissu propre sur la plaie.","explain3":"Compression directe = seul geste efficace immédiatement. Maintenir sans relâcher. Si le tissu se gorge, en ajouter un par-dessus sans retirer."},
  {"id":"73","type1":"VI","q1":"Actionnez le dégivrage de la lunette arrière et montrez le voyant ou le repère correspondant.","a1":"Appuyer sur le bouton de dégivrage lunette arrière (symbole rectangle + lignes horizontales) et montrer le voyant allumé.","explain1":"Des filaments dans la vitre chauffent pour éliminer le givre. La lunette doit être entièrement dégagée avant de rouler pour voir en arrière.","q2":"Quelle peut être la conséquence d'une panne de dégivrage de la lunette arrière ?","a2":"L'insuffisance ou l'absence de visibilité vers l'arrière.","explain2":"En hiver sans dégivrage, le rétroviseur intérieur est inutilisable. Risque accru lors des manœuvres et des changements de voie.","q3":"Hors autoroute ou endroit dangereux, en cas de panne ou d'accident, où doit être placé le triangle de pré-signalisation ?","a3":"À environ 30 m de la panne ou de l'accident, ou avant un virage, ou avant un sommet de côte.","explain3":"Sur autoroute, ne JAMAIS placer le triangle — trop dangereux. 30 m = environ 10 grandes enjambées. Toujours mettre le gilet avant de sortir."},
  {"id":"74","type1":"VE","q1":"Contrôlez l'état, la propreté et le fonctionnement de tous les clignotants côté trottoir.","a1":"Vérification des clignotants avant, latéral et arrière côté trottoir : propres, en bon état et fonctionnant. Toute anomalie signalée.","explain1":"Pour vérifier seul : activer les clignotants et faire le tour du véhicule, ou observer le reflet dans une vitrine.","q2":"Quelle est la signification d'un clignotement plus rapide que d'habitude ?","a2":"Le non-fonctionnement de l'une des ampoules.","explain2":"Le système accélère le clignotement pour alerter le conducteur. À corriger rapidement : les autres usagers ne voient plus tes intentions.","q3":"Quelles sont les précautions à prendre pour réaliser le dégagement d'urgence d'une victime en présence d'un danger réel, immédiat et non contrôlable ?","a3":"La victime doit être visible, facile à atteindre, rien ne doit gêner son dégagement, et on doit être sûr de pouvoir le réaliser.","explain3":"Le dégagement d'urgence comporte des risques pour la victime. Il ne se justifie que si le danger (incendie…) est certain et immédiat."},
  {"id":"75","type1":"VI","q1":"Montrez le voyant d'alerte signalant une pression insuffisante d'huile dans le moteur.","a1":"Montrer le voyant en forme de lampe à huile (icône rouge) sur le tableau de bord.","explain1":"Ce voyant rouge est critique. S'il s'allume en roulant → arrêter IMMÉDIATEMENT le moteur. Continuer = destruction moteur en quelques minutes.","q2":"Quelles sont les conditions à respecter pour compléter le niveau d'huile ?","a2":"Moteur froid et sur un terrain plat.","explain2":"Moteur chaud = huile dilatée, niveau faussé. En pente, l'huile se répartit inégalement dans le carter, rendant la lecture erronée.","q3":"Quelles sont les trois informations à transmettre aux services de secours ?","a3":"Le numéro de téléphone à partir duquel l'appel est émis, la nature et la localisation la plus précise du problème.","explain3":"Mémo : QUI (numéro), QUOI (nature), OÙ (localisation). Ces 3 infos permettent d'envoyer les bons moyens au bon endroit rapidement.","requiredCount3":3},
  {"id":"76","type1":"VE","q1":"Contrôlez l'état, la propreté et le fonctionnement des feux de détresse à l'avant et à l'arrière.","a1":"Vérification des feux de détresse : propres, en bon état et fonctionnant. Toute anomalie signalée.","explain1":"Les feux de détresse (tous les clignotants simultanément) signalent un danger ou une immobilisation soudaine aux autres usagers.","q2":"Dans quels cas doit-on les utiliser ?","a2":"En cas de panne, d'accident ou de ralentissement important.","explain2":"Utile aussi sur autoroute pour avertir les véhicules suivants d'un bouchon soudain. Ne pas oublier de les éteindre ensuite.","q3":"Dans quel cas peut-on positionner une victime en Position Latérale de Sécurité (PLS) ?","a3":"Si la victime ne répond pas, ne réagit pas et respire.","explain3":"PLS = inconsciente MAIS respire. Si elle ne respire plus → RCP. Si elle est consciente → ne pas la déplacer, des blessures sont possibles."},
  {"id":"77","type1":"VI","q1":"Vérifiez la présence de l'éthylotest.","a1":"Montrer l'éthylotest présent dans le véhicule (obligatoire, généralement dans la boîte à gants).","explain1":"Obligatoire depuis 2012. L'éthylotest permet de contrôler son propre taux d'alcoolémie avant de prendre le volant.","q2":"À partir de quel taux d'alcoolémie, en période de permis probatoire, est-on en infraction ?","a2":"0,2 g/l — c'est-à-dire 0 verre, car dès le 1er verre ce seuil peut être dépassé.","explain2":"Permis probatoire : seuil 0,2 g/l (quasi-zéro). Permis classique : 0,5 g/l. Un seul verre représente un risque réel d'infraction.","q3":"Quel comportement doit-on adopter en présence d'une victime en arrêt cardiaque ?","a3":"Alerter immédiatement les secours. Pratiquer une réanimation cardio-pulmonaire. Utiliser un défibrillateur (DAE) si possible.","explain3":"Mémo AMD : Alerter, Masser, Défibriller. Chaque minute sans RCP = -10% de survie. Ne pas attendre les secours pour commencer."},
  {"id":"78","type1":"VE","q1":"Contrôlez l'état, la propreté et le fonctionnement des feux de route.","a1":"Vérification des feux de route : propres, en bon état et fonctionnant. Toute anomalie signalée.","explain1":"Les feux de route éclairent jusqu'à 100 m (contre 50 m pour les feux de croisement). Il faut les passer en croisement dès qu'un véhicule arrive.","q2":"Citez un cas d'utilisation de l'appel lumineux.","a2":"Pour avertir de son approche, en cas de danger, ou à la place de l'avertisseur sonore.","explain2":"L'appel lumineux est plus discret et accepté que le klaxon. En agglomération, le klaxon est interdit sauf danger immédiat.","q3":"En cas de panne ou d'accident, quel équipement de sécurité doit être porté avant de quitter le véhicule ?","a3":"Le gilet de haute visibilité.","explain3":"Porter le gilet AVANT de sortir du véhicule, même sur le bord d'une route tranquille. Il multiplie la distance de détection par 3 à 4."},
  {"id":"79","type1":"VI","q1":"Positionnez la commande pour diriger l'air vers le pare-brise.","a1":"Orienter le sélecteur de ventilation vers l'icône pare-brise (désembuage), ou utiliser la position auto si disponible.","explain1":"La position pare-brise concentre l'air chaud sur la vitre pour désembuer rapidement. Combiner avec la clim pour un air sec et efficace.","q2":"Citez deux éléments complémentaires permettant un désembuage efficace.","a2":"La commande de vitesse de ventilation, la commande d'air chaud, et la climatisation.","explain2":"La clim assèche l'air et accélère drastiquement le désembuage même en hiver. Contre-intuitif mais très efficace.","requiredCount2":2,"q3":"Quel est l'objectif du Signal d'Alerte et d'Information des Populations (SAIP) ?","a3":"Avertir la population d'un danger imminent ou qu'un événement grave est en train de se produire.","explain3":"Le SAIP peut déclencher des sirènes et envoyer des notifications push via l'application dédiée pour alerter un maximum de personnes."},
  {"id":"80","type1":"VE","q1":"Montrez où doit s'effectuer le contrôle du niveau d'huile moteur.","a1":"Le candidat montre la jauge. Pas de manipulation exigée. Si besoin, l'accompagnateur peut indiquer comment ouvrir le capot.","explain1":"La jauge d'huile (tige MIN/MAX) se lit moteur froid et sur terrain plat. Un niveau bas risque la casse moteur immédiate.","q2":"Quel est le principal risque d'un manque d'huile moteur ?","a2":"Un risque de détérioration ou de casse du moteur.","explain2":"L'huile lubrifie toutes les pièces métalliques en mouvement. Sans elle, les frottements provoquent une surchauffe et une destruction rapide.","q3":"Comment est diffusée l'alerte émise par le Signal d'Alerte et d'Information aux Populations (SAIP) ?","a3":"Grâce aux sirènes, aux médias comme Radio France et France Télévision, ou grâce à l'application SAIP.","explain3":"Le SAIP utilise plusieurs canaux simultanément pour toucher un maximum de personnes. L'application envoie aussi des notifications push."},
  {"id":"81","type1":"VI","q1":"De quelle couleur est le voyant qui indique une défaillance du système de freinage ?","a1":"Le voyant de défaillance du système de freinage est de couleur rouge.","explain1":"Un voyant rouge de freinage allumé en roulant est une urgence absolue : s'arrêter prudemment. Cela peut signaler une fuite ou une défaillance grave.","q2":"Quel est le risque de circuler avec un frein de parking mal desserré ?","a2":"Une dégradation du système de freinage.","explain2":"Le frein de parking applique en permanence les garnitures sur les disques ou tambours. La friction constante les use et chauffe dangereusement.","q3":"En général, en cas de panne ou d'accident, où doit être placé le triangle de pré-signalisation ?","a3":"Le triangle de pré-signalisation doit être placé à une distance d'environ 30 m de la panne ou de l'accident, ou avant un virage ou un sommet de côte.","explain3":"30 m laisse le temps aux conducteurs arrivant de freiner avant le danger. Toujours mettre le gilet avant de sortir du véhicule."},
  {"id":"82","type1":"VE","q1":"Contrôlez l'état, la propreté et le fonctionnement des feux de croisement.","a1":"Vérification des feux, propres, en bon état et fonctionnent (toute anomalie doit être signalée).","explain1":"Les feux de croisement éclairent 50 m devant et s'inclinent vers le bas pour ne pas éblouir. À utiliser dès la tombée de la nuit.","q2":"Quelles sont les conséquences d'un mauvais réglage de ces feux ?","a2":"Une mauvaise vision vers l'avant et un risque d'éblouissement des autres usagers.","explain2":"Des feux trop hauts = éblouissement systématique. Trop bas = visibilité insuffisante. Réglage à revoir après un chargement lourd.","q3":"Dans quelle situation peut-on déplacer une victime ?","a3":"En présence d'un danger réel, immédiat, non contrôlable. Ce déplacement doit rester exceptionnel.","explain3":"Un mouvement brusque peut transformer une fracture vertébrale en tétraplégie. Ne déplacer que si danger vital immédiat."},
  {"id":"83","type1":"VI","q1":"Montrez le voyant d'alerte signalant une température trop élevée du liquide de refroidissement.","a1":"Montrer le voyant de température du liquide de refroidissement (icône thermomètre dans le liquide, généralement rouge) sur le tableau de bord.","explain1":"Si ce voyant s'allume en roulant, arrêter le moteur dès que possible. Continuer = surchauffe et destruction moteur garanties.","q2":"Quelle est la conséquence d'une température trop élevée de ce liquide ?","a2":"La surchauffe ou la casse moteur.","explain2":"Le liquide de refroidissement dissipe la chaleur du moteur. S'il ne remplit plus ce rôle, les pièces métalliques se dilatent et se grippent.","q3":"Lors d'un appel avec les services de secours, pourquoi devez-vous attendre que votre correspondant vous autorise à raccrocher ?","a3":"Car il peut nous conseiller ou nous guider dans la réalisation des gestes à faire, ou ne pas faire, jusqu'à l'arrivée des secours.","explain3":"L'opérateur des secours peut transmettre des instructions vitales en temps réel. Raccrocher prématurément peut priver la victime d'aide cruciale."},
  {"id":"84","type1":"VE","q1":"Sur le flanc d'un pneumatique, désignez le repère du témoin d'usure de la bande de roulement.","a1":"Désigner le triangle ou la mention TWI (Tread Wear Indicator) gravé sur le flanc, qui indique l'emplacement du témoin d'usure.","explain1":"Le témoin d'usure est une petite saillie dans les rainures. Quand la bande de roulement arrive à son niveau, le pneu est au minimum légal (1,6 mm) mais dangereux sur sol mouillé.","q2":"Qu'est-ce que l'aquaplanage, et quelle peut être sa conséquence ?","a2":"La présence d'un film d'eau entre le pneumatique et la chaussée pouvant entraîner une perte de contrôle du véhicule.","explain2":"Les rainures évacuent l'eau. Un pneu usé ne peut plus le faire efficacement : la roue se soulève et perd tout contact avec la chaussée.","q3":"Si un dégagement d'urgence de la victime est nécessaire, où doit-elle être déplacée ?","a3":"Dans un endroit suffisamment éloigné du danger et de ses conséquences.","explain3":"Le dégagement d'urgence ne se justifie qu'en présence d'un danger immédiat non maîtrisable. La victime doit être mise hors de portée du danger."},
  {"id":"85","type1":"VI","q1":"Actionnez les feux de détresse.","a1":"Actionner le bouton de feux de détresse (losange rouge) : tous les clignotants clignotent simultanément.","explain1":"Le bouton de détresse est toujours un losange rouge, facilement identifiable même en urgence. Il doit fonctionner clé retirée.","q2":"Dans quels cas doit-on les utiliser ?","a2":"En cas de panne, d'accident ou de ralentissement important.","explain2":"Les feux de détresse avertissent les autres conducteurs d'un danger imprévu. Sur autoroute, ils signalent aussi les bouchons soudains.","q3":"Quels comportements adopter en cas de diffusion du signal d'alerte du Système d'Alerte et d'Information des Populations (SAIP) ?","a3":"- Se mettre en sécurité. - S'informer grâce aux médias et sites internet des autorités dès que leur consultation est possible. - Respecter les consignes des autorités.","explain3":"Le SAIP est déclenché pour des dangers graves (catastrophe naturelle, attentat…). S'informer et obéir aux consignes des autorités est la réaction adaptée."},
  {"id":"86","type1":"VE","q1":"A l'aide de la plaque indicative, donnez la pression préconisée pour les pneumatiques arrières, véhicule chargé.","a1":"Lire la pression indiquée sur la plaque (généralement sur le montant de la portière conducteur) pour les pneus arrière en charge.","explain1":"La pression recommandée varie selon l'essieu et la charge. Sous-gonfler les pneus arrière d'un véhicule chargé augmente l'usure et les risques de crevaison.","q2":"A quelle fréquence est-il préconisé de vérifier la pression des pneus ?","a2":"Chaque mois pour une utilisation normale de son véhicule et avant chaque long trajet.","explain2":"La pression diminue naturellement avec le temps et les variations de température. Une vérification mensuelle permet de maintenir le niveau correct.","q3":"Comment et pourquoi protéger une zone de danger en cas d'accident de la route ?","a3":"En délimitant clairement et largement la zone de danger de façon visible pour protéger les victimes et éviter un sur-accident.","explain3":"Le sur-accident est une cause fréquente de victimes supplémentaires. Baliser tôt et visiblement protège les victimes et les secouristes."},
  {"id":"87","type1":"VI","q1":"Montrez la commande permettant de désactiver l'airbag du passager avant.","a1":"Montrer la commande de désactivation de l'airbag passager (généralement par clé ou bouton, souvent côté passager ou tableau de bord).","explain1":"L'airbag avant peut blesser grièvement un enfant en siège dos à la route. Sa désactivation est obligatoire dans ce cas pour éviter le choc du déploiement.","q2":"Dans quelle situation doit-on le désactiver ?","a2":"Lors du transport d'un enfant dans un siège auto dos à la route.","explain2":"Un siège dos à la route positionne la tête de l'enfant à quelques centimètres de l'airbag. En cas de déclenchement, l'impact peut être fatal.","q3":"Quelles sont les conditions pour réaliser le dégagement d'urgence d'une victime en présence d'un danger réel, immédiat et non contrôlable ?","a3":"La victime doit être visible, facile à atteindre et rien ne doit gêner son dégagement. Il faut être sûr(e) de pouvoir réaliser le dégagement de la victime.","explain3":"Le dégagement d'urgence comporte des risques pour la victime et le sauveteur. Il ne se justifie que si le danger (incendie, noyade...) est certain et immédiat."},
  {"id":"88","type1":"VE","q1":"Indiquez où se situe la sécurité enfant sur l'une des portières à l'arrière du véhicule.","a1":"Montrer le mécanisme de sécurité enfant situé sur le bord intérieur de la portière arrière, généralement un levier ou un interrupteur.","explain1":"Ce dispositif empêche l'ouverture de la portière depuis l'intérieur, évitant qu'un enfant ne l'ouvre accidentellement pendant le trajet.","q2":"Si la sécurité enfant est enclenchée, est-il possible d'ouvrir la portière arrière depuis l'extérieur ?","a2":"Oui.","explain2":"La sécurité enfant ne bloque que l'ouverture de l'intérieur. L'ouverture depuis l'extérieur reste possible pour permettre la sortie de l'enfant.","q3":"Quels sont les risques pour une personne victime d'une hémorragie ?","a3":"Entraîner pour la victime une détresse circulatoire ou un arrêt cardiaque.","explain3":"Une perte de sang importante réduit le volume sanguin circulant. Le cœur et le cerveau ne sont plus irrigués, pouvant causer l'arrêt cardiaque."},
  {"id":"89","type1":"VI","q1":"Montrez le voyant signalant l'absence de bouclage de la ceinture de sécurité du conducteur.","a1":"Montrer le voyant de ceinture non bouclée (icône personne avec ceinture barrée, généralement rouge ou orange) sur le tableau de bord.","explain1":"Ce voyant rappelle de boucler la ceinture avant de partir. La ceinture est le premier équipement de sécurité passive : son port réduit le risque de mort par 2 en cas d'accident.","q2":"En règle générale, à partir de quel âge un enfant peut-il être installé sur le siège passager avant du véhicule ?","a2":"10 ans.","explain2":"Avant 10 ans, les enfants doivent être attachés à l'arrière avec un dispositif adapté à leur taille. À l'avant, l'airbag représente un danger supplémentaire.","q3":"Comment est composé le signal d'alerte du Système d'Alerte et d'Information des Populations (SAIP) diffusé par les sirènes ?","a3":"Il se compose de deux codes distincts : - le Signal National d'Alerte (SNA), variation du signal sur trois cycles successifs. - Le signal de fin d'alerte, signal continu.","explain3":"Le signal modulé (montée/descente) signifie danger en cours. Le signal continu signifie fin d'alerte. Distinguer les deux évite panique inutile ou complacency dangereuse."},
  {"id":"90","type1":"VE","q1":"Avec l'assistance de l'accompagnateur, contrôlez l'état, la propreté et le fonctionnement des feux de stop.","a1":"Vérification des feux de stop : propres, en bon état et fonctionnent (toute anomalie doit être signalée).","explain1":"Les feux de stop préviennent les véhicules suiveurs d'un freinage. Un feu défaillant augmente le risque de collision arrière, surtout à vitesse élevée.","q2":"Quelle est la conséquence en cas de panne des feux de stop ?","a2":"Un manque d'information pour les usagers suiveurs et un risque de collision.","explain2":"Sans feux de stop, les conducteurs derrière ne peuvent pas anticiper ton freinage. Le risque de tamponnade est maximal sur autoroute ou route rapide.","q3":"Lors d'un appel avec les services de secours, pourquoi devez-vous attendre que votre correspondant vous autorise à raccrocher ?","a3":"Car il peut nous conseiller ou nous guider dans la réalisation des gestes à faire, ou ne pas faire, jusqu'à l'arrivée des secours.","explain3":"L'opérateur des secours peut donner des instructions vitales en temps réel. Raccrocher trop tôt prive la victime d'une assistance précieuse."},
  {"id":"91","type1":"VI","q1":"Allumez le(s) feu(x) de brouillard arrière(s) et montrez le voyant correspondant.","a1":"Actionner la commande des feux de brouillard arrière et montrer le voyant orange ou ambré s'allumant sur le tableau de bord.","explain1":"Le feu de brouillard arrière est visible jusqu'à 150 m dans le brouillard. Connaître son voyant évite de le laisser allumé par temps clair.","q2":"Pouvez-vous les utiliser par forte pluie ?","a2":"Non.","explain2":"Le feu antibrouillard arrière éblouit les conducteurs qui suivent par temps clair ou de pluie. Son usage est strictement réservé au brouillard dense.","q3":"Quels sont les signes d'un arrêt cardiaque ?","a3":"La victime ne répond pas, ne réagit pas et ne respire pas, ou présente une respiration anormale.","explain3":"Ces trois critères permettent de reconnaître rapidement l'arrêt cardiaque et de déclencher les secours sans perdre de temps à chercher le pouls."},
  {"id":"92","type1":"VE","q1":"Vérifiez l'état, la propreté et le fonctionnement des feux diurnes.","a1":"Vérification des feux diurnes : propres, en bon état et qui fonctionnent (toute anomalie doit être signalée).","explain1":"Les feux diurnes s'allument automatiquement. Ils améliorent la visibilité du véhicule le jour sans consommer autant que les feux de croisement.","q2":"Quelle est leur utilité ?","a2":"Rendre le véhicule plus visible le jour.","explain2":"Les études montrent que les feux diurnes réduisent les accidents frontaux. Ils signalent ta présence aux autres usagers même en plein jour.","q3":"A quel moment pouvez-vous mettre fin à un appel avec les secours ?","a3":"Uniquement lorsque notre correspondant nous invite à le faire.","explain3":"L'opérateur peut avoir besoin d'informations supplémentaires ou guider les gestes de secours en temps réel. Attendre sa permission garantit une prise en charge optimale."},
  {"id":"93","type1":"VI","q1":"Montrez la commande de recyclage de l'air.","a1":"Montrer le bouton de recyclage de l'air (icône personne dans une boucle ou flèche circulaire) sur la commande de climatisation.","explain1":"Le recyclage coupe l'arrivée d'air extérieur. Il permet d'éviter les odeurs ou fumées en ville, mais provoque de la buée si maintenu trop longtemps.","q2":"Quel peut être le risque de maintenir le recyclage de l'air de manière prolongée ?","a2":"Un risque de mauvaise visibilité par l'apparition de buée sur les surfaces vitrées.","explain2":"Sans renouvellement d'air, l'humidité s'accumule dans l'habitacle. La buée réduit la visibilité et peut provoquer des erreurs d'appréciation.","q3":"Quels sont les risques pour une personne en perte de connaissance qui est allongée sur le dos ?","a3":"L'arrêt respiratoire et l'arrêt cardiaque.","explain3":"Sur le dos, la langue peut obstruer les voies aériennes. La PLS (position latérale de sécurité) maintient les voies dégagées et prévient l'asphyxie."},
  {"id":"94","type1":"VE","q1":"Vérifiez la présence du triangle de pré-signalisation.","a1":"Montrer le triangle de pré-signalisation rangé dans le coffre ou son emplacement prévu dans le véhicule.","explain1":"Le triangle balise la zone de danger à 30 m du véhicule en panne hors agglomération. Son absence en cas de besoin aggrave le risque de sur-accident.","q2":"Utilise-t-on le triangle de pré-signalisation sur autoroute ?","a2":"Non.","explain2":"Sur autoroute, la vitesse des véhicules rend la pose du triangle extrêmement dangereuse. On utilise les feux de détresse et le gilet réfléchissant.","q3":"Quel comportement doit-on adopter en présence d'une victime en arrêt cardiaque ?","a3":"- ALERTER: alerter immédiatement les secours. - MASSER: pratiquer une réanimation cardio-pulmonaire. - DEFIBRILLER: utiliser un défibrillateur automatique (DAE) si possible.","explain3":"La chaîne de survie (alerter, masser, défibriller) multiplie par 3 les chances de survie. Chaque maillon est indispensable pour maximiser les chances."},
  {"id":"95","type1":"VI","q1":"Allumez les feux de route et montrez le voyant correspondant.","a1":"Actionner la commande des feux de route (plein phares) et montrer le voyant bleu s'allumant sur le tableau de bord.","explain1":"Le voyant bleu des feux de route rappelle qu'ils sont allumés. Il faut les éteindre dès qu'un véhicule arrive en face pour éviter l'éblouissement.","q2":"Quel est le risque de maintenir les feux de route lors d'un croisement avec d'autres usagers ?","a2":"Un risque d'éblouissement des autres usagers.","explain2":"Les feux de route éclairent 150 m mais éblouissent frontalement. L'éblouissement provoque une cécité momentanée pouvant durer plusieurs secondes.","q3":"Quel est l'objectif du Signal d'Alerte et d'Information des Populations (SAIP) ?","a3":"Avertir la population d'un danger imminent ou qu'un événement grave est en train de se produire.","explain3":"Le SAIP déclenche des sirènes pour alerter la population. Connaître son signal permet de réagir rapidement et de suivre les consignes des autorités."},
  {"id":"96","type1":"VE","q1":"Montrez où s'effectue le changement d'une ampoule à l'avant du véhicule.","a1":"Indiquer l'emplacement du bloc optique avant (sous le capot ou par l'extérieur selon le modèle). Si difficultés, l'accompagnateur peut aider à ouvrir le capot.","explain1":"Connaître l'accès aux blocs optiques avant permet d'intervenir rapidement. Un feu avant défaillant réduit la visibilité et risque de confondre le véhicule avec un deux-roues.","q2":"Quelles sont les conséquences en cas de panne d'un feu de croisement ?","a2":"Une mauvaise visibilité et le risque d'être confondu avec un deux roues.","explain2":"Un feu de croisement en panne rend le véhicule asymétrique et peu visible. De nuit, d'autres usagers peuvent le prendre pour un deux-roues et se positionner mal.","q3":"Citez les trois manières d'évaluer l'état de conscience d'une victime ?","a3":"- Lui poser des questions simples (\"comment ça va ?\", \"vous m'entendez ?\"). - Lui secouer doucement les épaules. - Lui prendre la main en lui demandant d'exécuter un geste simple (\"serrez-moi la main\").","explain3":"Évaluer la conscience guide la suite : victime consciente = surveiller ; inconsciente = alerter et vérifier la respiration avant tout autre geste."},
  {"id":"97","type1":"VI","q1":"Faites fonctionner l'essuie-glace arrière du véhicule.","a1":"Actionner la commande de l'essuie-glace arrière (généralement sur le combiné de colonne de direction) et vérifier son bon fonctionnement.","explain1":"L'essuie-glace arrière maintient la visibilité vers l'arrière par temps de pluie. Un essuie-glace défaillant rend les manœuvres et les rétroviseurs moins efficaces.","q2":"Pour une bonne visibilité vers l'arrière, en plus de l'utilisation de l'essuie-glace, quelle commande pouvez-vous actionner par temps de pluie ?","a2":"La commande de désembuage arrière. Le terme dégivrage peut remplacer celui de désembuage.","explain2":"Le désembuage arrière chauffe le lunette arrière via des filaments électriques. Combiné à l'essuie-glace, il garantit une visibilité optimale vers l'arrière.","q3":"Quels comportements adopter en présence d'une victime qui ne répond pas et ne réagit pas, mais respire ?","a3":"- La placer en position stable sur le côté ou position latérale de sécurité. - Alerter les secours. - Surveiller la respiration de la victime jusqu'à l'arrivée des secours.","explain3":"La PLS protège les voies aériennes d'une personne inconsciente. La surveiller permet de détecter toute dégradation et d'informer les secours en temps réel."},
  {"id":"98","type1":"VE","q1":"Montrez où s'effectue le changement d'une ampoule à l'arrière du véhicule.","a1":"Montrer l'emplacement des ampoules arrière (bloc optique arrière accessible depuis le coffre ou l'extérieur). Indiquer comment y accéder.","explain1":"Connaître l'accès aux blocs optiques arrière permet d'intervenir rapidement. Un feu arrière défaillant est dangereux la nuit et sanctionné au contrôle technique.","q2":"Quelles sont les conséquences en cas de panne d'un feu de position arrière ?","a2":"Être mal vu et un risque de collision.","explain2":"Un feu de position arrière en panne rend le véhicule quasi invisible la nuit pour les véhicules suiveurs, augmentant fortement le risque de collision arrière.","q3":"Comment est diffusée l'alerte émise par le Signal d'Alerte et d'Information aux Populations (SAIP) ?","a3":"Grâce aux sirènes, aux médias tels que Radio France et France Télévision ou encore grâce à l'application SAIP.","explain3":"La diversification des canaux garantit que l'alerte touche le maximum de personnes, y compris celles sans accès aux sirènes ou à internet."},
  {"id":"99","type1":"VI","q1":"Montrez le voyant indiquant une baisse de pression d'air d'un pneumatique.","a1":"Pour info : obligatoire sur tous les véhicules neufs mis en circulation à compter du 01/11/2014.","explain1":"Le voyant TPMS (pneu en coupe avec point d'exclamation) signale une perte de pression. S'il s'allume, vérifier la pression de tous les pneus rapidement.","q2":"A quelle fréquence est-il préconisé de vérifier la pression d'air des pneumatiques ?","a2":"Tous les mois.","explain2":"La pression des pneus diminue naturellement. Une vérification mensuelle à froid permet d'éviter une surconsommation, une usure irrégulière et un risque de crevaison.","q3":"Qu'est ce qu'un arrêt cardiaque ?","a3":"Le cœur ne fonctionne plus ou fonctionne d'une façon anarchique.","explain3":"Un arrêt cardiaque arrête la circulation sanguine. Sans massage cardiaque dans les premières minutes, les séquelles neurologiques sont inévitables."},
  {"id":"00","type1":"VE","q1":"Montrez où se situent les gicleurs de lave-glace avant.","a1":"Indiquer les gicleurs sur le capot ou en bas du pare-brise selon le modèle. Les vérifier propres et non obturés.","explain1":"Des gicleurs bouchés ou mal orientés ne nettoient plus le pare-brise. Les vérifier régulièrement évite une perte de visibilité soudaine.","q2":"Quelle est la principale conséquence d'un dispositif de lave-glace défaillant ?","a2":"Une mauvaise visibilité due à l'impossibilité de nettoyer le pare-brise.","explain2":"Sans lave-glace fonctionnel, une projection de boue rend le pare-brise opaque en quelques secondes. Particulièrement dangereux derrière un camion.","q3":"Qu'est ce qu'un défibrillateur automatisé externe (DAE) ?","a3":"C'est un appareil qui peut permettre de rétablir une activité cardiaque normale à une victime en arrêt cardiaque.","explain3":"Le DAE délivre un choc électrique pour resynchroniser le cœur. Il est guidé par instructions vocales et accessible au grand public."},
]

export function getScenarioById(id) {
  return SCENARIOS.find(s => s.id === String(id).padStart(2, '0')) || null
}